INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Banana Bread','classic-banana-bread','A moist and tender banana bread made with ripe bananas and warm spices. It is the perfect way to use overripe bananas sitting on your counter.','A soft and flavorful banana bread that comes together in under an hour.','American','Easy',10,60,70,8,210,4,35,7,2,'[{"amount":3,"unit":"whole","item":"ripe bananas","group":"Wet"},{"amount":0.33,"unit":"cup","item":"melted butter","group":"Wet"},{"amount":0.75,"unit":"cup","item":"granulated sugar","group":"Wet"},{"amount":1,"unit":"whole","item":"large egg","group":"Wet"},{"amount":1,"unit":"teaspoon","item":"vanilla extract","group":"Wet"},{"amount":1.5,"unit":"cups","item":"all-purpose flour","group":"Dry"},{"amount":1,"unit":"teaspoon","item":"baking soda","group":"Dry"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"Dry"},{"amount":0.5,"unit":"teaspoon","item":"ground cinnamon","group":"Dry"}]','[{"title":"Preheat and Prepare","text":"Preheat your oven to 350 degrees F. Grease a 9x5 inch loaf pan with butter or non-stick spray and set aside.","timer":0},{"title":"Mash the Bananas","text":"In a large mixing bowl, mash the ripe bananas with a fork until completely smooth. Stir in the melted butter until well combined.","timer":0},{"title":"Mix the Wet Ingredients","text":"Mix the sugar, egg, and vanilla extract into the banana mixture until everything is well incorporated.","timer":0},{"title":"Add the Dry Ingredients","text":"Sprinkle the baking soda, salt, and cinnamon over the wet mixture. Add the flour and fold gently until just combined. Do not overmix or the bread will become tough.","timer":0},{"title":"Bake","text":"Pour the batter into the prepared loaf pan and bake for 55 to 65 minutes until a toothpick inserted in the center comes out clean. Let cool in the pan for 10 minutes before slicing.","timer":3600}]','[{"original":"butter","swap":"coconut oil or vegetable oil"},{"original":"granulated sugar","swap":"brown sugar or honey"},{"original":"all-purpose flour","swap":"whole wheat flour"}]','["Using bananas that are not ripe enough which results in less sweetness and moisture","Overmixing the batter which leads to a dense and tough loaf","Opening the oven door too early which causes the bread to sink in the middle"]','["banana","bread","baking","quick bread","comfort food"]','["vegetarian"]','Baking','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Meatloaf','classic-meatloaf','A hearty and satisfying meatloaf made with ground beef, aromatics, and a tangy ketchup glaze. This timeless comfort food is perfect for a weeknight family dinner.','A juicy and flavorful meatloaf topped with a sweet and tangy glaze.','American','Easy',15,65,80,6,380,28,18,22,1,'[{"amount":2,"unit":"lbs","item":"ground beef 80 percent lean","group":"Main"},{"amount":1,"unit":"whole","item":"medium onion finely diced","group":"Main"},{"amount":2,"unit":"whole","item":"garlic cloves minced","group":"Main"},{"amount":2,"unit":"whole","item":"large eggs","group":"Binder"},{"amount":0.5,"unit":"cup","item":"breadcrumbs","group":"Binder"},{"amount":0.33,"unit":"cup","item":"whole milk","group":"Binder"},{"amount":2,"unit":"tablespoons","item":"Worcestershire sauce","group":"Seasoning"},{"amount":0.5,"unit":"cup","item":"ketchup divided","group":"Glaze"},{"amount":2,"unit":"tablespoons","item":"brown sugar","group":"Glaze"}]','[{"title":"Preheat and Prepare Pan","text":"Preheat the oven to 350 degrees F. Line a rimmed baking sheet or loaf pan with foil and lightly grease it.","timer":0},{"title":"Make the Glaze","text":"In a small bowl, combine half the ketchup with the brown sugar and stir until smooth. Set aside for topping.","timer":0},{"title":"Mix the Meatloaf","text":"In a large bowl, combine the ground beef, onion, garlic, eggs, breadcrumbs, milk, Worcestershire sauce, and remaining ketchup. Mix with your hands until just combined. Do not overmix.","timer":0},{"title":"Shape and Glaze","text":"Transfer the mixture to the prepared pan and shape it into a loaf approximately 9 inches long. Spread the ketchup glaze evenly over the top.","timer":0},{"title":"Bake and Rest","text":"Bake for 60 to 70 minutes until the internal temperature reaches 160 degrees F. Let the meatloaf rest for 10 minutes before slicing and serving.","timer":3900}]','[{"original":"ground beef","swap":"ground turkey or a beef and pork blend"},{"original":"breadcrumbs","swap":"crushed crackers or rolled oats"},{"original":"whole milk","swap":"beef broth or evaporated milk"}]','["Overmixing the meat mixture which results in a dense and rubbery texture","Using very lean ground beef which makes the loaf dry and crumbly","Skipping the resting period which causes the loaf to fall apart when sliced"]','["meatloaf","beef","comfort food","dinner","classic"]','[]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Chili Con Carne','chili-con-carne','A bold and smoky chili packed with ground beef, kidney beans, and a rich blend of chili spices. This warming pot of chili is ideal for game day or a cold evening.','A deeply flavored beef and bean chili with a perfect smoky kick.','Tex-Mex','Medium',15,45,60,6,420,32,28,18,8,'[{"amount":1.5,"unit":"lbs","item":"ground beef","group":"Main"},{"amount":1,"unit":"whole","item":"large onion diced","group":"Aromatics"},{"amount":3,"unit":"whole","item":"garlic cloves minced","group":"Aromatics"},{"amount":1,"unit":"can","item":"28 oz crushed tomatoes","group":"Base"},{"amount":2,"unit":"cans","item":"15 oz kidney beans drained","group":"Base"},{"amount":2,"unit":"tablespoons","item":"chili powder","group":"Spices"},{"amount":1,"unit":"teaspoon","item":"ground cumin","group":"Spices"},{"amount":1,"unit":"teaspoon","item":"smoked paprika","group":"Spices"},{"amount":1,"unit":"cup","item":"beef broth","group":"Base"}]','[{"title":"Brown the Beef","text":"Heat a large pot or Dutch oven over medium-high heat. Add the ground beef and cook until browned, breaking it apart with a spoon. Drain excess fat and set the beef aside.","timer":480},{"title":"Cook the Aromatics","text":"In the same pot, add the diced onion and cook over medium heat for 4 to 5 minutes until softened. Add the garlic and cook for 1 more minute until fragrant.","timer":360},{"title":"Add Spices and Tomatoes","text":"Stir in the chili powder, cumin, and smoked paprika and cook for 1 minute to bloom the spices. Add the crushed tomatoes, beef broth, and browned beef. Stir well to combine.","timer":60},{"title":"Add Beans and Simmer","text":"Stir in the drained kidney beans. Bring the chili to a boil, then reduce heat to low and simmer uncovered for 30 minutes, stirring occasionally.","timer":1800},{"title":"Season and Serve","text":"Taste and adjust salt and spice levels. Serve hot topped with shredded cheese, sour cream, or sliced green onions.","timer":0}]','[{"original":"ground beef","swap":"ground turkey or plant-based ground meat"},{"original":"kidney beans","swap":"black beans or pinto beans"},{"original":"beef broth","swap":"chicken broth or water with a bouillon cube"}]','["Not blooming the spices in the pot which results in a flat and dull flavor","Simmering on too high a heat which causes the chili to burn on the bottom","Adding too much liquid which makes the chili thin and watery instead of thick"]','["chili","beef","beans","spicy","game day","comfort food"]','["gluten-free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Fluffy Pancakes','classic-fluffy-pancakes','Light and airy pancakes with a golden crust and tender interior that are perfect for a weekend breakfast. They cook up quickly and pair wonderfully with maple syrup and fresh fruit.','Thick and fluffy homemade pancakes ready in under 20 minutes.','American','Easy',5,15,20,4,280,8,42,9,1,'[{"amount":1.5,"unit":"cups","item":"all-purpose flour","group":"Dry"},{"amount":2,"unit":"tablespoons","item":"granulated sugar","group":"Dry"},{"amount":2,"unit":"teaspoons","item":"baking powder","group":"Dry"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"Dry"},{"amount":1.25,"unit":"cups","item":"whole milk","group":"Wet"},{"amount":1,"unit":"whole","item":"large egg","group":"Wet"},{"amount":3,"unit":"tablespoons","item":"melted butter","group":"Wet"},{"amount":1,"unit":"teaspoon","item":"vanilla extract","group":"Wet"}]','[{"title":"Mix the Dry Ingredients","text":"In a large bowl, whisk together the flour, sugar, baking powder, and salt until evenly combined.","timer":0},{"title":"Mix the Wet Ingredients","text":"In a separate bowl, whisk together the milk, egg, melted butter, and vanilla extract until smooth.","timer":0},{"title":"Combine the Batter","text":"Pour the wet ingredients into the dry ingredients and stir gently until just combined. The batter should be slightly lumpy. Do not overmix or the pancakes will be tough.","timer":0},{"title":"Heat the Pan","text":"Heat a non-stick skillet or griddle over medium heat and lightly grease with butter. The pan is ready when a drop of water sizzles and evaporates immediately.","timer":120},{"title":"Cook the Pancakes","text":"Pour about one quarter cup of batter per pancake onto the skillet. Cook until bubbles form on the surface and the edges look set, about 2 minutes. Flip and cook for another 1 to 2 minutes until golden brown. Serve immediately.","timer":240}]','[{"original":"whole milk","swap":"buttermilk or oat milk"},{"original":"butter","swap":"vegetable oil or coconut oil"},{"original":"all-purpose flour","swap":"a 1 to 1 gluten-free flour blend"}]','["Overmixing the batter which develops gluten and produces flat dense pancakes","Cooking on too high a heat which burns the outside before the inside is cooked through","Flipping the pancakes more than once which deflates them and makes them chewy"]','["pancakes","breakfast","brunch","quick","fluffy"]','["vegetarian"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Chocolate Chip Cookies','chocolate-chip-cookies','Golden and chewy chocolate chip cookies with crisp edges and gooey chocolate pools in every bite. This foolproof recipe delivers bakery-quality results every single time.','Perfectly chewy and golden chocolate chip cookies loaded with melted chocolate.','American','Easy',15,12,27,24,180,2,24,9,1,'[{"amount":2.25,"unit":"cups","item":"all-purpose flour","group":"Dry"},{"amount":1,"unit":"teaspoon","item":"baking soda","group":"Dry"},{"amount":1,"unit":"teaspoon","item":"salt","group":"Dry"},{"amount":1,"unit":"cup","item":"unsalted butter softened","group":"Wet"},{"amount":0.75,"unit":"cup","item":"granulated sugar","group":"Wet"},{"amount":0.75,"unit":"cup","item":"packed brown sugar","group":"Wet"},{"amount":2,"unit":"whole","item":"large eggs","group":"Wet"},{"amount":2,"unit":"teaspoons","item":"vanilla extract","group":"Wet"},{"amount":2,"unit":"cups","item":"semi-sweet chocolate chips","group":"Mix-in"}]','[{"title":"Preheat and Prep","text":"Preheat the oven to 375 degrees F. Line two baking sheets with parchment paper and set aside.","timer":0},{"title":"Cream the Butter and Sugars","text":"In a large bowl, beat the softened butter, granulated sugar, and brown sugar together with a hand mixer or stand mixer on medium speed for 2 to 3 minutes until light and fluffy.","timer":180},{"title":"Add Wet Ingredients","text":"Add the eggs one at a time, beating well after each addition. Mix in the vanilla extract until fully combined.","timer":0},{"title":"Combine and Add Chocolate","text":"In a separate bowl, whisk together the flour, baking soda, and salt. Gradually add the dry ingredients to the wet ingredients and mix until just combined. Fold in the chocolate chips.","timer":0},{"title":"Scoop and Bake","text":"Drop rounded tablespoons of dough onto the prepared baking sheets, spacing them 2 inches apart. Bake for 9 to 11 minutes until the edges are golden but the centers still look slightly underdone. Let cool on the pan for 5 minutes before transferring.","timer":660}]','[{"original":"unsalted butter","swap":"vegan butter or coconut oil at room temperature"},{"original":"semi-sweet chocolate chips","swap":"dark chocolate chunks or milk chocolate chips"},{"original":"all-purpose flour","swap":"bread flour for chewier cookies"}]','["Using melted instead of softened butter which causes the cookies to spread too thin","Overbaking the cookies since they continue to cook on the hot pan after removal from the oven","Not measuring flour correctly by scooping directly from the bag which packs too much flour and makes cookies dry"]','["cookies","chocolate chip","baking","dessert","classic"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic French Toast','classic-french-toast','Golden and crispy on the outside with a soft custardy center, this French toast is a breakfast staple. It comes together in minutes with simple pantry ingredients.','A quick and delicious breakfast made with egg-soaked bread cooked to golden perfection.','French','Easy',5,10,15,4,280,10,34,11,1,'[{"amount":8,"unit":"slices","item":"thick-cut brioche bread","group":"main"},{"amount":3,"unit":"large","item":"eggs","group":"custard"},{"amount":0.75,"unit":"cup","item":"whole milk","group":"custard"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"custard"},{"amount":1,"unit":"tsp","item":"ground cinnamon","group":"custard"},{"amount":2,"unit":"tbsp","item":"granulated sugar","group":"custard"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"cooking"},{"amount":1,"unit":"pinch","item":"salt","group":"custard"}]','[{"title":"Make the Custard","text":"In a shallow bowl, whisk together the eggs, whole milk, vanilla extract, ground cinnamon, granulated sugar, and salt until fully combined and smooth.","timer":0},{"title":"Soak the Bread","text":"Dip each slice of brioche into the custard mixture, letting it soak for about 20 seconds per side so the bread absorbs the mixture without falling apart.","timer":40},{"title":"Heat the Pan","text":"Place a large non-stick skillet or griddle over medium heat and melt one tablespoon of butter, swirling to coat the surface evenly.","timer":60},{"title":"Cook the Toast","text":"Cook the soaked bread slices for 2 to 3 minutes per side until deep golden brown. Work in batches and add more butter as needed between batches.","timer":300},{"title":"Serve Immediately","text":"Transfer the French toast to plates and serve immediately with maple syrup, powdered sugar, or fresh berries on top.","timer":0}]','[{"original":"brioche bread","swap":"thick-cut white sandwich bread or challah"},{"original":"whole milk","swap":"half-and-half or oat milk"},{"original":"unsalted butter","swap":"coconut oil or a neutral cooking spray"}]','["Soaking the bread too long causes it to become soggy and fall apart in the pan","Cooking over high heat burns the outside before the inside is cooked through","Using thin bread results in a limp texture with no structure"]','["breakfast","quick","family-friendly","classic","brunch"]','["vegetarian"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Beef Lasagna','classic-beef-lasagna','Layers of rich meat sauce, creamy ricotta, and gooey melted cheese make this lasagna the ultimate comfort food. It is hearty, satisfying, and perfect for feeding a crowd.','A hearty baked pasta dish layered with meat sauce, ricotta, and melted mozzarella cheese.','Italian','Medium',30,60,90,8,520,32,38,26,3,'[{"amount":12,"unit":"sheets","item":"lasagna noodles","group":"pasta"},{"amount":1,"unit":"lb","item":"ground beef","group":"meat sauce"},{"amount":2,"unit":"cups","item":"marinara sauce","group":"meat sauce"},{"amount":15,"unit":"oz","item":"whole milk ricotta cheese","group":"cheese layer"},{"amount":2,"unit":"cups","item":"shredded mozzarella cheese","group":"cheese layer"},{"amount":0.5,"unit":"cup","item":"grated Parmesan cheese","group":"cheese layer"},{"amount":1,"unit":"large","item":"egg","group":"cheese layer"},{"amount":2,"unit":"tsp","item":"Italian seasoning","group":"meat sauce"}]','[{"title":"Cook Noodles and Meat","text":"Boil the lasagna noodles according to package directions until al dente, then drain. In a skillet over medium heat, brown the ground beef, drain excess fat, and stir in the marinara sauce and Italian seasoning. Simmer for 5 minutes.","timer":900},{"title":"Mix the Ricotta Layer","text":"In a medium bowl, stir together the ricotta cheese, egg, half of the Parmesan cheese, and a pinch of salt and pepper until smooth and well combined.","timer":0},{"title":"Layer the Lasagna","text":"Preheat the oven to 375 degrees F. Spread a thin layer of meat sauce on the bottom of a 9x13 baking dish. Layer noodles, ricotta mixture, meat sauce, and mozzarella. Repeat the layers twice and finish with sauce and remaining mozzarella and Parmesan on top.","timer":0},{"title":"Bake Covered","text":"Cover the baking dish tightly with aluminum foil and bake at 375 degrees F for 40 minutes so the cheese melts and the layers heat through evenly.","timer":2400},{"title":"Uncover and Brown","text":"Remove the foil and bake for an additional 15 to 20 minutes until the top is bubbly and golden brown. Let the lasagna rest for 15 minutes before slicing and serving.","timer":1200}]','[{"original":"ground beef","swap":"ground turkey or Italian sausage"},{"original":"whole milk ricotta","swap":"cottage cheese blended until smooth"},{"original":"lasagna noodles","swap":"no-boil lasagna noodles to save time"}]','["Skipping the resting time causes the lasagna to fall apart when sliced","Not covering with foil while baking causes the top to burn before the center is hot","Overcooking the noodles before baking makes them mushy after the oven"]','["dinner","comfort food","Italian","baked","meal prep"]','[]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Fettuccine Alfredo','creamy-fettuccine-alfredo','This rich and velvety Alfredo pasta comes together with just a few ingredients for a restaurant-quality result at home. The sauce clings beautifully to every strand of fettuccine.','Silky fettuccine tossed in a rich Parmesan cream sauce ready in under 30 minutes.','Italian','Easy',5,20,25,4,610,18,62,34,2,'[{"amount":12,"unit":"oz","item":"fettuccine pasta","group":"pasta"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":1.5,"unit":"cups","item":"heavy cream","group":"sauce"},{"amount":1.5,"unit":"cups","item":"freshly grated Parmesan cheese","group":"sauce"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"cup","item":"pasta cooking water","group":"sauce"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of heavily salted water to a boil and cook the fettuccine until al dente according to package directions. Reserve one quarter cup of pasta water before draining.","timer":720},{"title":"Saute the Garlic","text":"In a large skillet over medium heat, melt the butter and add the minced garlic. Cook for 1 to 2 minutes until fragrant, stirring constantly so the garlic does not brown.","timer":120},{"title":"Build the Sauce","text":"Pour the heavy cream into the skillet and bring it to a gentle simmer over medium-low heat. Stir frequently and let it cook for 3 to 4 minutes until it thickens slightly.","timer":240},{"title":"Add the Cheese","text":"Remove the skillet from heat and stir in the grated Parmesan cheese, salt, and black pepper until the sauce is smooth. Add a splash of reserved pasta water if the sauce is too thick.","timer":0},{"title":"Toss and Serve","text":"Add the drained fettuccine directly to the sauce and toss well to coat every strand. Serve immediately with extra Parmesan and freshly cracked pepper on top.","timer":0}]','[{"original":"heavy cream","swap":"half-and-half for a lighter sauce"},{"original":"fettuccine","swap":"linguine or pappardelle"},{"original":"freshly grated Parmesan","swap":"Pecorino Romano for a sharper flavor"}]','["Using pre-shredded Parmesan causes the sauce to become grainy and clumpy","Cooking the sauce over high heat causes the cream to break and separate","Not reserving pasta water leaves you without a way to loosen a sauce that is too thick"]','["pasta","dinner","quick","comfort food","Italian","vegetarian"]','["vegetarian"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Fudgy Chocolate Brownies','fudgy-chocolate-brownies','These dense and fudgy brownies have a crinkly top and an intensely chocolatey center that will satisfy any sweet tooth. They bake in one bowl with no mixer required.','Rich and fudgy one-bowl chocolate brownies with a glossy crinkle top.','American','Easy',10,25,35,16,210,3,28,11,1,'[{"amount":0.5,"unit":"cup","item":"unsalted butter","group":"base"},{"amount":1,"unit":"cup","item":"granulated sugar","group":"base"},{"amount":2,"unit":"large","item":"eggs","group":"base"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"base"},{"amount":0.5,"unit":"cup","item":"all-purpose flour","group":"dry"},{"amount":0.5,"unit":"cup","item":"unsweetened cocoa powder","group":"dry"},{"amount":0.25,"unit":"tsp","item":"salt","group":"dry"},{"amount":0.5,"unit":"cup","item":"chocolate chips","group":"mix-in"}]','[{"title":"Preheat and Prep","text":"Preheat the oven to 350 degrees F. Grease an 8x8 inch baking pan and line it with parchment paper, leaving an overhang on two sides for easy removal.","timer":0},{"title":"Melt Butter and Mix Wet Ingredients","text":"Melt the butter in a large microwave-safe bowl in 30-second intervals. Whisk in the granulated sugar until combined, then whisk in the eggs one at a time followed by the vanilla extract.","timer":0},{"title":"Add Dry Ingredients","text":"Sift the cocoa powder, all-purpose flour, and salt directly into the wet ingredients. Fold gently with a spatula until just combined and do not overmix. Fold in the chocolate chips.","timer":0},{"title":"Bake the Brownies","text":"Pour the batter into the prepared pan and spread it into an even layer. Bake at 350 degrees F for 23 to 25 minutes until a toothpick inserted in the center comes out with moist crumbs.","timer":1500},{"title":"Cool Before Cutting","text":"Let the brownies cool completely in the pan for at least 30 minutes before lifting them out with the parchment overhang and cutting into 16 squares.","timer":1800}]','[{"original":"unsalted butter","swap":"coconut oil for a slightly different flavor"},{"original":"all-purpose flour","swap":"a one-to-one gluten-free flour blend"},{"original":"chocolate chips","swap":"chopped walnuts or pecans"}]','["Overmixing the batter after adding flour makes the brownies tough and cakey","Overbaking by even a few minutes dries out the fudgy texture completely","Cutting into the brownies while they are still hot causes them to crumble and fall apart"]','["dessert","chocolate","baking","one-bowl","crowd-pleaser"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Stovetop Mac and Cheese','creamy-stovetop-mac-and-cheese','This stovetop mac and cheese is ultra creamy, cheesy, and ready in about 20 minutes with no baking required. It uses a simple roux-based sauce that coats every piece of pasta perfectly.','Ultra creamy stovetop macaroni and cheese made with a rich cheddar sauce in under 25 minutes.','American','Easy',5,20,25,4,540,22,58,24,2,'[{"amount":12,"unit":"oz","item":"elbow macaroni","group":"pasta"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":2,"unit":"tbsp","item":"all-purpose flour","group":"sauce"},{"amount":2,"unit":"cups","item":"whole milk","group":"sauce"},{"amount":2,"unit":"cups","item":"shredded sharp cheddar cheese","group":"sauce"},{"amount":0.5,"unit":"tsp","item":"mustard powder","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"seasoning"}]','[{"title":"Cook the Macaroni","text":"Bring a large pot of salted water to a boil and cook the elbow macaroni until al dente according to package directions. Drain and set aside.","timer":600},{"title":"Make the Roux","text":"In a medium saucepan over medium heat, melt the butter. Add the flour and whisk constantly for 1 to 2 minutes until the mixture turns light golden and smells slightly nutty.","timer":120},{"title":"Build the Bechamel","text":"Slowly pour in the whole milk while whisking constantly to prevent lumps. Continue to cook and whisk over medium heat for 4 to 5 minutes until the sauce thickens enough to coat the back of a spoon.","timer":300},{"title":"Melt in the Cheese","text":"Remove the saucepan from heat and stir in the shredded cheddar cheese, mustard powder, salt, and black pepper until the cheese is fully melted and the sauce is smooth.","timer":0},{"title":"Combine and Serve","text":"Add the drained macaroni to the cheese sauce and stir well to coat every piece evenly. Serve immediately straight from the pot while it is hot and at its creamiest.","timer":0}]','[{"original":"sharp cheddar cheese","swap":"Gruyere or a mix of cheddar and Gouda"},{"original":"whole milk","swap":"evaporated milk for an extra creamy texture"},{"original":"elbow macaroni","swap":"cavatappi or shells to hold more sauce"}]','["Adding cheese while the sauce is still on high heat causes it to become grainy and oily","Using pre-shredded bagged cheese results in a gritty sauce due to added starch coatings","Not whisking the roux constantly causes lumps that are difficult to smooth out later"]','["comfort food","quick","dinner","family-friendly","stovetop","American"]','["vegetarian"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Sourdough Bread','classic-sourdough-bread','A rustic sourdough loaf with a crispy crust and chewy open crumb. This recipe uses a wild yeast starter for deep tangy flavor.','Artisan sourdough bread made with a wild yeast starter and simple ingredients.','American','Hard',30,45,75,12,180,6,36,1,2,'[{"amount":450,"unit":"g","item":"bread flour","group":"dough"},{"amount":325,"unit":"ml","item":"warm water","group":"dough"},{"amount":100,"unit":"g","item":"active sourdough starter","group":"dough"},{"amount":9,"unit":"g","item":"fine sea salt","group":"dough"},{"amount":1,"unit":"tbsp","item":"rice flour","group":"dusting"},{"amount":1,"unit":"tbsp","item":"all purpose flour","group":"dusting"},{"amount":50,"unit":"g","item":"whole wheat flour","group":"dough"},{"amount":1,"unit":"tsp","item":"honey","group":"dough"}]','[{"title":"Mix the Dough","text":"Combine bread flour, whole wheat flour, warm water, active sourdough starter, and honey in a large bowl. Mix until no dry flour remains. Cover and rest for 30 minutes to allow autolyse.","timer":1800},{"title":"Add Salt and Stretch","text":"Sprinkle salt over the dough and incorporate it by pinching and folding. Perform 4 sets of stretch and fold every 30 minutes over 2 hours. The dough should become smooth and elastic.","timer":7200},{"title":"Bulk Fermentation","text":"Cover the bowl and allow the dough to bulk ferment at room temperature for 4 to 6 hours until it has grown by 50 percent. Do not rush this step as it builds flavor.","timer":18000},{"title":"Shape and Proof","text":"Turn dough onto a lightly floured surface and shape into a tight round boule. Place seam side up into a floured banneton. Cover and refrigerate overnight for 8 to 12 hours.","timer":43200},{"title":"Bake in Dutch Oven","text":"Preheat oven and Dutch oven to 250 degrees Celsius for 1 hour. Score the cold dough and place into the hot Dutch oven. Bake covered for 20 minutes then uncovered for 25 minutes until deep brown.","timer":2700}]','[{"original":"bread flour","swap":"all purpose flour for a slightly denser loaf"},{"original":"sourdough starter","swap":"instant yeast at 7g for a faster non-tangy version"},{"original":"honey","swap":"maple syrup or omit entirely"}]','["Using a starter that is not active or bubbly enough before mixing the dough","Cutting into the loaf too soon before it has fully cooled which ruins the crumb structure","Skipping the stretch and fold steps which are essential for gluten development"]','["sourdough","bread","artisan","fermented","baking"]','["vegan","dairy-free"]','Bread','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Chicken Tikka Masala','chicken-tikka-masala','Tender marinated chicken in a rich, spiced tomato cream sauce. This beloved dish balances smoky grilled chicken with a velvety masala gravy.','Smoky grilled chicken pieces simmered in a creamy spiced tomato sauce.','Indian','Medium',20,40,60,4,520,42,18,28,3,'[{"amount":700,"unit":"g","item":"boneless chicken thighs cut into chunks","group":"chicken"},{"amount":200,"unit":"g","item":"plain full fat yogurt","group":"marinade"},{"amount":3,"unit":"tbsp","item":"tikka masala spice blend","group":"spices"},{"amount":400,"unit":"g","item":"crushed canned tomatoes","group":"sauce"},{"amount":200,"unit":"ml","item":"heavy cream","group":"sauce"},{"amount":1,"unit":"large","item":"white onion finely diced","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tbsp","item":"fresh ginger grated","group":"sauce"},{"amount":2,"unit":"tbsp","item":"neutral cooking oil","group":"sauce"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"}]','[{"title":"Marinate the Chicken","text":"Mix yogurt with half the tikka masala spice blend and salt. Coat chicken chunks thoroughly and marinate for at least 1 hour or overnight in the refrigerator for best flavor.","timer":3600},{"title":"Grill or Broil the Chicken","text":"Cook marinated chicken under a hot broiler or on a grill pan for 8 to 10 minutes turning once until charred at the edges and cooked through. Set aside and do not discard the resting juices.","timer":600},{"title":"Build the Masala Sauce","text":"Heat oil in a large pan over medium heat. Saute onion for 8 minutes until golden. Add garlic and ginger and cook for 2 minutes. Stir in remaining spice blend and toast for 1 minute until fragrant.","timer":660},{"title":"Simmer the Sauce","text":"Pour in crushed tomatoes and bring to a gentle simmer. Cook uncovered for 15 minutes until the sauce thickens and deepens in color. Stir in heavy cream and simmer for 5 more minutes.","timer":1200},{"title":"Combine and Finish","text":"Add the grilled chicken and any resting juices into the sauce. Stir well and simmer together for 5 minutes so the chicken absorbs the sauce. Taste and adjust salt before serving with rice or naan.","timer":300}]','[{"original":"heavy cream","swap":"full fat coconut cream for a dairy free version"},{"original":"chicken thighs","swap":"chickpeas or paneer for a vegetarian option"},{"original":"plain yogurt","swap":"coconut yogurt to keep the dish dairy free"}]','["Not marinating the chicken long enough which results in less flavorful and dry meat","Skipping the broiling step and adding raw chicken directly to the sauce losing the smoky char","Adding cream over high heat which can cause it to curdle and separate"]','["indian","chicken","curry","creamy","spicy"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Authentic Pad Thai','authentic-pad-thai','A classic Thai stir fried noodle dish with shrimp, egg, and crunchy peanuts in a tangy tamarind sauce. Quick to cook but packed with bold umami flavors.','Thai rice noodles stir fried with shrimp, egg, and a tangy tamarind based sauce.','Thai','Medium',15,15,30,2,610,34,72,18,3,'[{"amount":200,"unit":"g","item":"flat rice noodles","group":"noodles"},{"amount":200,"unit":"g","item":"medium shrimp peeled and deveined","group":"protein"},{"amount":3,"unit":"large","item":"eggs","group":"protein"},{"amount":3,"unit":"tbsp","item":"tamarind paste","group":"sauce"},{"amount":2,"unit":"tbsp","item":"fish sauce","group":"sauce"},{"amount":1,"unit":"tbsp","item":"palm sugar or brown sugar","group":"sauce"},{"amount":3,"unit":"stalks","item":"green onions sliced","group":"garnish"},{"amount":50,"unit":"g","item":"dry roasted peanuts roughly chopped","group":"garnish"},{"amount":2,"unit":"tbsp","item":"neutral high heat oil","group":"cooking"},{"amount":1,"unit":"cup","item":"bean sprouts","group":"garnish"}]','[{"title":"Soak the Noodles","text":"Soak rice noodles in room temperature water for 30 minutes until pliable but still slightly firm. Do not use boiling water or the noodles will become mushy during stir frying. Drain and set aside.","timer":1800},{"title":"Mix the Sauce","text":"Whisk together tamarind paste, fish sauce, and palm sugar in a small bowl until the sugar dissolves. Taste and adjust the balance of sour, salty, and sweet to your preference. Set aside.","timer":120},{"title":"Cook the Shrimp","text":"Heat a wok over very high heat until smoking. Add oil and stir fry shrimp for 2 minutes until pink and cooked through. Push shrimp to the side and crack eggs into the wok. Scramble until just set.","timer":180},{"title":"Stir Fry the Noodles","text":"Add drained noodles to the wok and pour sauce over everything. Toss constantly using tongs for 2 to 3 minutes until noodles absorb the sauce and develop slight caramelization. Add a splash of water if noodles stick.","timer":180},{"title":"Garnish and Serve","text":"Remove from heat and toss in half the green onions and half the bean sprouts. Divide between plates and top with remaining bean sprouts, peanuts, and green onions. Serve with lime wedges and chili flakes.","timer":60}]','[{"original":"shrimp","swap":"firm tofu pressed and cubed for a vegetarian version"},{"original":"fish sauce","swap":"soy sauce or tamari for a vegan alternative"},{"original":"tamarind paste","swap":"lime juice mixed with a small amount of worcestershire sauce"}]','["Using boiling water to soak noodles which makes them too soft and causes them to break during stir frying","Cooking on low heat instead of very high heat which steams rather than stir fries the noodles","Overcrowding the wok which drops the temperature and results in soggy noodles"]','["thai","noodles","stir fry","shrimp","asian"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Butter Chicken','creamy-butter-chicken','Melt in your mouth chicken in a luscious mildly spiced tomato and butter sauce. This dish is milder than tikka masala making it a crowd pleasing favorite.','Tender chicken simmered in a velvety mildly spiced tomato butter cream sauce.','Indian','Medium',15,35,50,4,540,38,14,34,2,'[{"amount":700,"unit":"g","item":"boneless chicken breast cut into pieces","group":"chicken"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":400,"unit":"g","item":"crushed tomatoes","group":"sauce"},{"amount":200,"unit":"ml","item":"heavy cream","group":"sauce"},{"amount":1,"unit":"large","item":"onion finely chopped","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tsp","item":"garam masala","group":"spices"},{"amount":1,"unit":"tsp","item":"ground cumin","group":"spices"},{"amount":1,"unit":"tsp","item":"sweet paprika","group":"spices"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"}]','[{"title":"Sear the Chicken","text":"Season chicken pieces with salt, cumin, and paprika. Melt 2 tablespoons of butter in a large skillet over medium high heat. Sear chicken in batches for 3 to 4 minutes per side until golden. Remove and set aside.","timer":480},{"title":"Saute the Aromatics","text":"In the same skillet add remaining butter and saute onion over medium heat for 8 minutes until soft and golden brown. Add garlic and cook for 2 minutes until fragrant. Stir in garam masala and toast for 30 seconds.","timer":630},{"title":"Build the Tomato Sauce","text":"Pour crushed tomatoes into the skillet and stir well scraping up any browned bits from the bottom. Bring to a simmer and cook uncovered for 15 minutes until the sauce reduces and deepens in color.","timer":900},{"title":"Blend and Add Cream","text":"Use an immersion blender to puree the sauce until completely smooth. Stir in heavy cream and simmer on low heat for 5 minutes. Do not boil after adding cream as it may cause the sauce to separate.","timer":300},{"title":"Finish with Chicken","text":"Return the seared chicken to the sauce and stir to coat evenly. Simmer gently for 10 minutes until chicken is cooked through and has absorbed the sauce flavors. Serve with basmati rice and warm naan bread.","timer":600}]','[{"original":"heavy cream","swap":"coconut cream for a dairy free and slightly sweeter version"},{"original":"chicken breast","swap":"chicken thighs for more flavor and juicier results"},{"original":"unsalted butter","swap":"ghee for a more authentic and nutty flavor profile"}]','["Not blending the sauce which is essential for achieving the signature silky smooth texture","Boiling the sauce after adding cream which causes it to curdle and become grainy","Overcooking the chicken during the initial sear making it dry and tough by the end"]','["indian","chicken","curry","creamy","mild"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Beef Tacos','classic-beef-tacos','Seasoned ground beef served in warm corn tortillas with fresh toppings and salsa. A simple and satisfying weeknight meal ready in under 30 minutes.','Spiced ground beef in corn tortillas topped with fresh salsa, cheese, and lime.','Mexican','Easy',10,15,25,4,430,28,32,22,4,'[{"amount":500,"unit":"g","item":"lean ground beef","group":"filling"},{"amount":8,"unit":"small","item":"corn tortillas","group":"shells"},{"amount":2,"unit":"tsp","item":"ground cumin","group":"spices"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"spices"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"spices"},{"amount":1,"unit":"tsp","item":"chili powder","group":"spices"},{"amount":100,"unit":"g","item":"shredded cheddar cheese","group":"toppings"},{"amount":1,"unit":"cup","item":"fresh pico de gallo","group":"toppings"},{"amount":1,"unit":"large","item":"lime cut into wedges","group":"toppings"},{"amount":1,"unit":"cup","item":"shredded iceberg lettuce","group":"toppings"}]','[{"title":"Mix the Taco Seasoning","text":"Combine cumin, smoked paprika, garlic powder, chili powder, and salt in a small bowl. This homemade blend is more flavorful than store bought packets and lets you control the heat level.","timer":60},{"title":"Brown the Ground Beef","text":"Heat a large skillet over medium high heat with no oil. Add ground beef and break it apart with a wooden spoon. Cook for 7 to 8 minutes until fully browned with no pink remaining. Drain excess fat.","timer":480},{"title":"Season the Meat","text":"Sprinkle the taco seasoning over the cooked beef and stir to coat evenly. Add 60 milliliters of water and stir to create a light sauce. Simmer for 3 minutes until the liquid reduces and meat is well coated.","timer":180},{"title":"Warm the Tortillas","text":"Heat corn tortillas directly over a gas flame for 20 seconds per side or in a dry skillet for 30 seconds per side until warm and slightly charred. Stack and keep wrapped in a clean towel to stay pliable.","timer":120},{"title":"Assemble and Serve","text":"Spoon seasoned beef into each warm tortilla. Top with shredded lettuce, pico de gallo, and cheddar cheese. Finish with a generous squeeze of fresh lime juice and serve immediately while warm.","timer":60}]','[{"original":"ground beef","swap":"ground turkey or ground chicken for a lighter option"},{"original":"corn tortillas","swap":"flour tortillas or crispy taco shells based on preference"},{"original":"cheddar cheese","swap":"cotija cheese or pepper jack for a more authentic flavor"}]','["Not draining the excess fat from the beef which makes the filling greasy and soggy","Skipping the step of warming tortillas which causes them to crack and fall apart when folded","Overloading the tacos with too many toppings making them impossible to eat without falling apart"]','["mexican","beef","tacos","quick","weeknight"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Fried Rice','classic-fried-rice','A savory and satisfying fried rice made with day-old rice, vegetables, and soy sauce. It comes together in under 20 minutes for a quick and delicious meal.','Quick and easy fried rice packed with vegetables and bold umami flavor.','Chinese','Easy',10,15,25,4,380,12,58,10,3,'[{"amount":3,"unit":"cups","item":"cooked day-old white rice","group":"base"},{"amount":3,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":2,"unit":"tbsp","item":"sesame oil","group":"oil"},{"amount":3,"unit":"whole","item":"large eggs","group":"protein"},{"amount":1,"unit":"cup","item":"frozen peas and carrots","group":"vegetables"},{"amount":3,"unit":"whole","item":"green onions chopped","group":"vegetables"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":1,"unit":"tbsp","item":"vegetable oil","group":"oil"},{"amount":1,"unit":"tsp","item":"white pepper","group":"seasoning"}]','[{"title":"Heat the Wok","text":"Heat a large wok or skillet over high heat and add vegetable oil. Allow the pan to get very hot before adding any ingredients to ensure proper searing.","timer":120},{"title":"Cook the Aromatics","text":"Add the minced garlic to the hot oil and stir fry for 30 seconds until fragrant. Do not let the garlic burn as it will make the dish bitter.","timer":30},{"title":"Scramble the Eggs","text":"Push the garlic to one side and crack the eggs into the pan. Scramble them quickly until just set, then break them into small pieces and mix with the garlic.","timer":60},{"title":"Add Rice and Vegetables","text":"Add the day-old rice and frozen vegetables to the pan. Stir fry everything together over high heat, breaking up any rice clumps for about 5 minutes.","timer":300},{"title":"Season and Finish","text":"Pour in the soy sauce and sesame oil, then toss everything together. Add white pepper and green onions, stir fry for one more minute, and serve immediately.","timer":60}]','[{"original":"white rice","swap":"brown rice or cauliflower rice"},{"original":"soy sauce","swap":"tamari or coconut aminos"},{"original":"vegetable oil","swap":"avocado oil or canola oil"}]','["Using freshly cooked rice which is too moist and makes the fried rice mushy","Cooking over low heat which steams the rice instead of frying it","Adding too much soy sauce which makes the dish overly salty and dark"]','["fried rice","quick","weeknight","asian","one-pan"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Caesar Salad','classic-caesar-salad','A crisp and bold Caesar salad featuring romaine lettuce, homemade dressing, and crunchy croutons. The tangy dressing is rich with garlic and parmesan for maximum flavor.','Crisp romaine tossed in a creamy homemade Caesar dressing with golden croutons.','American','Easy',15,10,25,4,310,9,22,22,3,'[{"amount":2,"unit":"heads","item":"romaine lettuce chopped","group":"base"},{"amount":0.5,"unit":"cup","item":"grated parmesan cheese","group":"topping"},{"amount":1,"unit":"cup","item":"cubed day-old bread for croutons","group":"topping"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"dressing"},{"amount":2,"unit":"tbsp","item":"lemon juice","group":"dressing"},{"amount":1,"unit":"tsp","item":"Dijon mustard","group":"dressing"},{"amount":0.5,"unit":"cup","item":"mayonnaise","group":"dressing"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"oil"},{"amount":1,"unit":"tsp","item":"Worcestershire sauce","group":"dressing"}]','[{"title":"Make the Croutons","text":"Toss the bread cubes with olive oil and a pinch of salt, then spread on a baking sheet. Bake at 375F for 10 minutes until golden and crispy.","timer":600},{"title":"Prepare the Dressing","text":"In a bowl, whisk together mayonnaise, lemon juice, Dijon mustard, Worcestershire sauce, and minced garlic until smooth and well combined.","timer":120},{"title":"Add Parmesan to Dressing","text":"Stir half of the grated parmesan into the dressing and season with salt and black pepper to taste. Adjust lemon juice for extra brightness if desired.","timer":60},{"title":"Toss the Salad","text":"Place the chopped romaine in a large salad bowl and drizzle the dressing over it. Toss well to ensure every leaf is evenly coated with the dressing.","timer":60},{"title":"Top and Serve","text":"Add the croutons and remaining parmesan on top of the salad. Serve immediately so the croutons remain crunchy and the lettuce stays crisp.","timer":30}]','[{"original":"mayonnaise","swap":"Greek yogurt for a lighter dressing"},{"original":"romaine lettuce","swap":"kale or little gem lettuce"},{"original":"day-old bread","swap":"store-bought croutons"}]','["Dressing the salad too far in advance which causes the lettuce to wilt","Using too much dressing which overwhelms the fresh crisp lettuce","Skipping the Worcestershire sauce which adds essential depth to the dressing"]','["salad","classic","caesar","quick","vegetarian"]','["vegetarian"]','Salad','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Fresh Homemade Guacamole','fresh-homemade-guacamole','A vibrant and chunky guacamole made with ripe avocados, lime juice, and fresh cilantro. It is the perfect dip for chips or a topping for tacos and burgers.','Creamy and fresh guacamole ready in just 10 minutes with simple ingredients.','Mexican','Easy',10,0,10,4,180,2,10,16,7,'[{"amount":3,"unit":"whole","item":"ripe avocados","group":"base"},{"amount":2,"unit":"tbsp","item":"fresh lime juice","group":"acid"},{"amount":0.25,"unit":"cup","item":"fresh cilantro chopped","group":"herbs"},{"amount":0.5,"unit":"whole","item":"red onion finely diced","group":"vegetables"},{"amount":1,"unit":"whole","item":"jalapeno seeded and minced","group":"vegetables"},{"amount":1,"unit":"whole","item":"roma tomato diced","group":"vegetables"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":0.75,"unit":"tsp","item":"kosher salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"cumin","group":"seasoning"}]','[{"title":"Prepare the Avocados","text":"Cut the avocados in half, remove the pits, and scoop the flesh into a large bowl. Do not use avocados that are too firm or too mushy for best results.","timer":60},{"title":"Mash the Avocado","text":"Use a fork to mash the avocado to your desired consistency. Leave it slightly chunky for texture rather than making it completely smooth.","timer":60},{"title":"Add Lime and Salt","text":"Immediately stir in the fresh lime juice and kosher salt. The lime juice adds bright flavor and also helps slow the browning of the avocado.","timer":30},{"title":"Mix in Remaining Ingredients","text":"Fold in the diced onion, jalapeno, tomato, garlic, cilantro, and cumin. Mix gently so the chunky texture of the guacamole is preserved.","timer":60},{"title":"Taste and Adjust","text":"Taste the guacamole and adjust salt and lime juice as needed. Serve immediately with tortilla chips or press plastic wrap directly on the surface to store.","timer":30}]','[{"original":"jalapeno","swap":"serrano pepper for more heat"},{"original":"red onion","swap":"white onion or shallots"},{"original":"fresh cilantro","swap":"fresh parsley for a cilantro-free version"}]','["Using underripe avocados which are hard to mash and lack creamy flavor","Adding tomatoes too early which releases water and makes the guacamole watery","Over-mashing the avocado until it becomes a smooth paste with no texture"]','["dip","mexican","avocado","no-cook","party"]','["vegan","gluten-free","dairy-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Homemade Hummus','creamy-homemade-hummus','A silky smooth hummus made from scratch with chickpeas, tahini, and lemon juice. It is far creamier than store-bought versions and incredibly easy to make.','Ultra-smooth hummus blended with tahini and lemon for a rich satisfying dip.','Middle Eastern','Easy',10,0,10,6,210,8,20,11,5,'[{"amount":2,"unit":"cans","item":"chickpeas drained and rinsed","group":"base"},{"amount":0.33,"unit":"cup","item":"tahini","group":"base"},{"amount":3,"unit":"tbsp","item":"fresh lemon juice","group":"acid"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":3,"unit":"tbsp","item":"ice cold water","group":"liquid"},{"amount":2,"unit":"tbsp","item":"olive oil plus more for serving","group":"oil"},{"amount":0.75,"unit":"tsp","item":"kosher salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"cumin","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"smoked paprika for garnish","group":"garnish"}]','[{"title":"Blend Tahini and Lemon","text":"Add the tahini and lemon juice to a food processor and blend for 90 seconds until the mixture becomes light and fluffy. This step is key for creamy hummus.","timer":90},{"title":"Add Garlic and Spices","text":"Add the minced garlic, cumin, and salt to the fluffy tahini mixture. Blend for another 30 seconds to fully incorporate the aromatics.","timer":30},{"title":"Add Chickpeas","text":"Add the drained chickpeas to the food processor. Blend for about 2 minutes, scraping down the sides of the bowl halfway through blending.","timer":120},{"title":"Add Water and Oil","text":"With the processor running, drizzle in the ice cold water and olive oil. Blend for another 60 seconds until the hummus is completely smooth and creamy.","timer":60},{"title":"Taste and Serve","text":"Taste and adjust salt and lemon juice. Spread into a shallow bowl, drizzle with olive oil, and sprinkle with smoked paprika. Serve with pita or vegetables.","timer":30}]','[{"original":"canned chickpeas","swap":"dried chickpeas soaked and cooked overnight"},{"original":"tahini","swap":"sunflower seed butter for a nut-free option"},{"original":"lemon juice","swap":"lime juice for a slightly different citrus note"}]','["Skipping the tahini and lemon blending step which is essential for a fluffy texture","Not blending long enough which leaves the hummus grainy instead of smooth","Using warm water instead of ice cold water which prevents the hummus from becoming light"]','["dip","middle eastern","chickpeas","no-cook","healthy"]','["vegan","gluten-free","dairy-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hearty Chicken Noodle Soup','hearty-chicken-noodle-soup','A comforting and flavorful chicken noodle soup loaded with tender chicken, vegetables, and egg noodles in a rich golden broth. It is the ultimate cozy meal for any occasion.','Classic homestyle chicken noodle soup with tender chicken and hearty vegetables.','American','Medium',15,45,60,6,320,28,30,8,3,'[{"amount":1.5,"unit":"lbs","item":"boneless skinless chicken breasts","group":"protein"},{"amount":8,"unit":"cups","item":"low sodium chicken broth","group":"liquid"},{"amount":3,"unit":"cups","item":"egg noodles uncooked","group":"pasta"},{"amount":3,"unit":"whole","item":"carrots sliced into rounds","group":"vegetables"},{"amount":3,"unit":"stalks","item":"celery sliced","group":"vegetables"},{"amount":1,"unit":"whole","item":"yellow onion diced","group":"vegetables"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":1,"unit":"tsp","item":"dried thyme","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"oil"}]','[{"title":"Saute the Vegetables","text":"Heat olive oil in a large pot over medium heat. Add the onion, carrots, and celery and cook for 5 minutes until softened. Add the garlic and cook for another minute.","timer":360},{"title":"Add Broth and Chicken","text":"Pour in the chicken broth and add the whole chicken breasts along with the dried thyme. Bring the soup to a boil, then reduce heat to a gentle simmer.","timer":300},{"title":"Cook the Chicken","text":"Simmer the chicken breasts in the broth for 20 minutes until fully cooked through. Remove the chicken with tongs and set aside on a cutting board to rest.","timer":1200},{"title":"Shred Chicken and Add Noodles","text":"Shred the cooked chicken into bite-sized pieces using two forks. Return the shredded chicken to the pot and add the egg noodles to the simmering broth.","timer":300},{"title":"Finish and Season","text":"Cook the noodles for 8 minutes until tender. Season the soup with salt and black pepper to taste. Serve hot with crusty bread on the side.","timer":480}]','[{"original":"egg noodles","swap":"rotini pasta or rice for a gluten-free option"},{"original":"chicken breasts","swap":"bone-in chicken thighs for richer flavor"},{"original":"dried thyme","swap":"fresh thyme or Italian seasoning blend"}]','["Boiling the soup too vigorously which makes the chicken tough and the broth cloudy","Adding the noodles too early which causes them to become overcooked and mushy","Using low-quality broth which results in a flat and bland tasting soup"]','["soup","comfort food","chicken","winter","classic"]','["dairy-free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Overnight Oats','overnight-oats','Creamy rolled oats soaked in milk overnight for a no-cook breakfast. Wake up to a ready-made meal packed with fiber and protein.','Prep these oats the night before for an effortless and nutritious morning breakfast.','American','Easy',10,0,10,2,320,12,48,8,6,'[{"amount":1,"unit":"cup","item":"rolled oats","group":"base"},{"amount":1,"unit":"cup","item":"milk of choice","group":"base"},{"amount":0.5,"unit":"cup","item":"plain Greek yogurt","group":"base"},{"amount":2,"unit":"tbsp","item":"chia seeds","group":"base"},{"amount":2,"unit":"tbsp","item":"maple syrup","group":"sweetener"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"flavoring"},{"amount":0.5,"unit":"cup","item":"fresh berries","group":"topping"},{"amount":2,"unit":"tbsp","item":"almond butter","group":"topping"}]','[{"title":"Combine base ingredients","text":"In a large bowl or jar, combine the rolled oats, milk, Greek yogurt, chia seeds, maple syrup, and vanilla extract. Stir well until everything is evenly mixed.","timer":0},{"title":"Divide into jars","text":"Divide the oat mixture evenly between two mason jars or airtight containers. Ensure the mixture is spread evenly so it soaks consistently.","timer":0},{"title":"Refrigerate overnight","text":"Seal the jars and place them in the refrigerator. Allow the oats to soak for a minimum of 6 hours or overnight for best results.","timer":21600},{"title":"Stir and adjust consistency","text":"In the morning, remove the jars and give the oats a good stir. If the mixture is too thick, add a splash of milk and stir again until you reach your desired consistency.","timer":0},{"title":"Add toppings and serve","text":"Top each jar with fresh berries and a spoonful of almond butter. Serve cold directly from the jar or transfer to a bowl.","timer":0}]','[{"original":"milk of choice","swap":"oat milk or coconut milk for a dairy-free option"},{"original":"maple syrup","swap":"honey or agave nectar"},{"original":"almond butter","swap":"peanut butter or sunflower seed butter"}]','["Using instant oats instead of rolled oats which results in a mushy texture","Not stirring the mixture thoroughly before refrigerating causing uneven soaking","Skipping the chia seeds which help thicken and bind the oats"]','["breakfast","meal prep","no cook","healthy","quick"]','["vegetarian","gluten-free option"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Smoothie Bowl','smoothie-bowl','A thick and vibrant blended fruit base topped with crunchy granola and fresh fruit. It is nutritious, colorful, and endlessly customizable.','Blend frozen fruit into a thick base and pile on your favorite toppings for a beautiful breakfast bowl.','American','Easy',10,0,10,2,380,10,62,9,8,'[{"amount":2,"unit":"cups","item":"frozen mixed berries","group":"base"},{"amount":1,"unit":"cup","item":"frozen banana slices","group":"base"},{"amount":0.5,"unit":"cup","item":"Greek yogurt","group":"base"},{"amount":0.25,"unit":"cup","item":"milk of choice","group":"base"},{"amount":0.5,"unit":"cup","item":"granola","group":"topping"},{"amount":0.5,"unit":"cup","item":"fresh sliced strawberries","group":"topping"},{"amount":2,"unit":"tbsp","item":"honey","group":"topping"},{"amount":2,"unit":"tbsp","item":"shredded coconut","group":"topping"}]','[{"title":"Blend the base","text":"Add the frozen berries, frozen banana, Greek yogurt, and milk to a high-powered blender. Blend until completely smooth, stopping to scrape down the sides as needed.","timer":60},{"title":"Check consistency","text":"The mixture should be very thick, almost like soft-serve ice cream. If it is too thin, add more frozen fruit. If it is too thick, add milk one tablespoon at a time.","timer":0},{"title":"Pour into bowls","text":"Divide the thick smoothie mixture evenly between two wide bowls. Work quickly as the mixture will begin to melt at room temperature.","timer":0},{"title":"Add toppings","text":"Arrange the granola, fresh strawberry slices, and shredded coconut on top of each bowl in rows or sections for a visually appealing presentation.","timer":0},{"title":"Drizzle and serve immediately","text":"Drizzle each bowl with honey and serve immediately before the smoothie base begins to melt. Eat with a spoon.","timer":0}]','[{"original":"frozen mixed berries","swap":"frozen mango or frozen acai packets"},{"original":"Greek yogurt","swap":"coconut yogurt for a dairy-free version"},{"original":"granola","swap":"hemp seeds or crushed nuts for a lower carb option"}]','["Adding too much liquid which makes the base runny instead of thick and spoonable","Using fresh fruit instead of frozen which prevents the thick creamy texture","Blending too long which warms up the mixture and causes it to become liquid"]','["breakfast","no cook","healthy","vegan option","colorful"]','["vegetarian","gluten-free option"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Avocado Toast','avocado-toast','Creamy smashed avocado on crispy toasted bread with a perfectly cooked egg on top. Simple ingredients come together for a satisfying and wholesome meal.','Toast bread, smash ripe avocado with seasoning, and top with a fried egg for a classic and delicious meal.','American','Easy',5,10,15,2,340,14,28,20,7,'[{"amount":2,"unit":"slices","item":"thick sourdough bread","group":"base"},{"amount":2,"unit":"whole","item":"ripe avocados","group":"topping"},{"amount":2,"unit":"whole","item":"large eggs","group":"topping"},{"amount":1,"unit":"tbsp","item":"fresh lemon juice","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"flaky sea salt","group":"seasoning"},{"amount":1,"unit":"tsp","item":"olive oil","group":"cooking"},{"amount":2,"unit":"tbsp","item":"everything bagel seasoning","group":"seasoning"}]','[{"title":"Toast the bread","text":"Place the sourdough slices in a toaster or under the broiler. Toast until golden brown and crispy on the outside while remaining slightly soft inside.","timer":180},{"title":"Smash the avocado","text":"Halve the avocados, remove the pits, and scoop the flesh into a bowl. Add the lemon juice and a pinch of salt, then smash with a fork to your preferred texture, chunky or smooth.","timer":0},{"title":"Fry the eggs","text":"Heat olive oil in a non-stick skillet over medium heat. Crack in the eggs and cook for 2 to 3 minutes for a runny yolk or 4 minutes for a fully set yolk.","timer":180},{"title":"Assemble the toast","text":"Spread the smashed avocado generously over each slice of toasted bread. Use the back of a spoon to spread it evenly all the way to the edges.","timer":0},{"title":"Top and season","text":"Place a fried egg on top of each toast. Sprinkle with red pepper flakes, everything bagel seasoning, and a pinch of flaky sea salt. Serve immediately.","timer":0}]','[{"original":"sourdough bread","swap":"whole grain bread or gluten-free bread"},{"original":"fried egg","swap":"poached egg or smoked salmon for variety"},{"original":"lemon juice","swap":"lime juice for a slightly different citrus flavor"}]','["Using underripe avocados which are hard and difficult to smash smoothly","Not seasoning the avocado enough which results in a bland topping","Assembling too early so the toast becomes soggy before serving"]','["breakfast","brunch","quick","healthy","vegetarian"]','["vegetarian","dairy-free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Egg Fried Rice','egg-fried-rice','Classic Chinese-style fried rice made with day-old rice, scrambled eggs, and savory soy sauce. It is a quick and satisfying meal ready in under 20 minutes.','Stir-fry day-old rice with eggs, vegetables, and soy sauce for a fast and flavorful one-pan meal.','Chinese','Easy',10,15,25,4,410,16,58,12,3,'[{"amount":3,"unit":"cups","item":"day-old cooked jasmine rice","group":"base"},{"amount":4,"unit":"whole","item":"large eggs","group":"protein"},{"amount":1,"unit":"cup","item":"frozen peas and carrots","group":"vegetables"},{"amount":3,"unit":"whole","item":"green onions sliced","group":"aromatics"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":3,"unit":"tbsp","item":"soy sauce","group":"seasoning"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"vegetable oil","group":"cooking"}]','[{"title":"Prepare the eggs","text":"Crack the eggs into a small bowl and beat them lightly with a fork. Season with a small pinch of salt. Set aside and keep near the stove.","timer":0},{"title":"Stir-fry aromatics and vegetables","text":"Heat vegetable oil in a large wok or skillet over high heat until smoking. Add the garlic and stir-fry for 30 seconds, then add the frozen peas and carrots and cook for 2 minutes.","timer":150},{"title":"Scramble the eggs","text":"Push the vegetables to one side of the wok. Pour the beaten eggs into the empty side and scramble them quickly with a spatula until just set but still slightly soft.","timer":60},{"title":"Add the rice","text":"Add the day-old rice to the wok and break up any clumps with the spatula. Stir-fry everything together on high heat for 3 to 4 minutes until the rice is heated through and slightly crispy.","timer":240},{"title":"Season and serve","text":"Pour in the soy sauce and sesame oil and toss everything together until evenly coated. Add the sliced green onions, give a final toss, and serve immediately in bowls.","timer":0}]','[{"original":"jasmine rice","swap":"brown rice or cauliflower rice for a healthier option"},{"original":"soy sauce","swap":"tamari for a gluten-free version"},{"original":"frozen peas and carrots","swap":"corn kernels or diced bell peppers"}]','["Using freshly cooked warm rice which is too moist and makes the fried rice sticky and clumpy","Cooking on low heat which steams the rice instead of giving it the signature wok-fried texture","Adding soy sauce too early which causes the rice to become too wet and lose its crispiness"]','["dinner","lunch","one pan","quick","Asian","leftovers"]','["dairy-free","vegetarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Ramen from Scratch','ramen-from-scratch','A rich and deeply savory tonkotsu-style pork broth loaded with tender noodles, soft-boiled eggs, and fresh toppings. Making ramen from scratch takes time but delivers an extraordinary bowl.','Simmer pork bones for hours to build a rich broth then assemble bowls with noodles and classic ramen toppings.','Japanese','Hard',30,270,300,4,680,38,72,24,4,'[{"amount":2,"unit":"lbs","item":"pork neck bones","group":"broth"},{"amount":8,"unit":"cups","item":"water","group":"broth"},{"amount":4,"unit":"whole","item":"garlic cloves smashed","group":"broth"},{"amount":1,"unit":"whole","item":"large onion halved","group":"broth"},{"amount":3,"unit":"tbsp","item":"soy sauce","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"white miso paste","group":"seasoning"},{"amount":4,"unit":"portions","item":"fresh or dried ramen noodles","group":"noodles"},{"amount":4,"unit":"whole","item":"large eggs","group":"topping"},{"amount":4,"unit":"slices","item":"chashu pork belly or cooked pork","group":"topping"},{"amount":4,"unit":"whole","item":"green onions thinly sliced","group":"topping"}]','[{"title":"Blanch the bones","text":"Place the pork bones in a large pot and cover with cold water. Bring to a boil over high heat and cook for 10 minutes. Drain and rinse the bones thoroughly under cold water to remove impurities.","timer":600},{"title":"Simmer the broth","text":"Return the cleaned bones to the pot with 8 cups of fresh water, smashed garlic, and halved onion. Bring to a boil then reduce to a vigorous simmer. Cook uncovered for 4 hours, adding water as needed to keep bones submerged.","timer":14400},{"title":"Prepare the soft-boiled eggs","text":"Bring a small pot of water to a boil. Gently lower in the eggs and cook for exactly 6 minutes and 30 seconds. Transfer immediately to an ice bath for 5 minutes then peel carefully. Marinate in soy sauce and water if desired.","timer":390},{"title":"Strain and season the broth","text":"Strain the broth through a fine mesh sieve and discard the solids. Return the clear broth to the pot and whisk in the miso paste and soy sauce. Taste and adjust seasoning. Keep hot over low heat.","timer":0},{"title":"Cook noodles and assemble bowls","text":"Cook the ramen noodles according to package directions, usually 2 to 3 minutes. Divide noodles among four large bowls. Ladle the hot broth over the noodles. Top each bowl with a halved soft-boiled egg, a slice of pork, and sliced green onions. Serve immediately.","timer":180}]','[{"original":"pork neck bones","swap":"chicken carcasses for a lighter chicken-based broth"},{"original":"white miso paste","swap":"red miso paste for a deeper and more robust flavor"},{"original":"fresh ramen noodles","swap":"dried soba noodles or instant ramen noodles in a pinch"}]','["Not blanching the bones first which leaves the broth cloudy and bitter from impurities","Simmering on too low a heat which produces a thin and watery broth instead of a rich creamy one","Overcooking the soft-boiled eggs which results in a fully set yolk instead of the desired jammy center"]','["dinner","Japanese","comfort food","weekend cooking","noodles","soup"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Crispy Fish Tacos','crispy-fish-tacos','Golden fried cod tucked into warm tortillas with crunchy slaw and creamy lime sauce. These tacos are fresh, bold, and ready in under 30 minutes.','Crispy battered cod in warm tortillas with tangy slaw and zesty lime crema.','Mexican','Easy',15,15,30,4,420,28,38,16,3,'[{"amount":1.5,"unit":"lb","item":"cod fillets cut into strips","group":"fish"},{"amount":1,"unit":"cup","item":"all purpose flour","group":"batter"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"batter"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"batter"},{"amount":1,"unit":"cup","item":"sparkling water","group":"batter"},{"amount":8,"unit":"pieces","item":"small corn tortillas","group":"base"},{"amount":2,"unit":"cups","item":"shredded cabbage","group":"slaw"},{"amount":0.5,"unit":"cup","item":"sour cream","group":"sauce"},{"amount":2,"unit":"pieces","item":"limes juiced","group":"sauce"},{"amount":2,"unit":"tbsp","item":"vegetable oil for frying","group":"cooking"}]','[{"title":"Make the Lime Crema","text":"In a small bowl whisk together sour cream and lime juice until smooth. Season with salt and set aside in the refrigerator.","timer":0},{"title":"Prepare the Batter","text":"In a large bowl combine flour smoked paprika and garlic powder. Slowly whisk in sparkling water until a smooth thin batter forms. Do not over mix.","timer":0},{"title":"Fry the Fish","text":"Heat oil in a large skillet over medium high heat. Dip cod strips into batter letting excess drip off then fry for 3 to 4 minutes per side until golden and crispy. Drain on paper towels.","timer":480},{"title":"Warm the Tortillas","text":"Place tortillas directly over a gas flame or in a dry skillet for 30 seconds per side until warmed and slightly charred.","timer":60},{"title":"Assemble the Tacos","text":"Layer each tortilla with shredded cabbage crispy fish strips and a generous drizzle of lime crema. Serve immediately with extra lime wedges.","timer":0}]','[{"original":"cod","swap":"tilapia or mahi mahi"},{"original":"sour cream","swap":"Greek yogurt"},{"original":"corn tortillas","swap":"flour tortillas"}]','["Using batter that is too thick which makes the coating heavy and doughy","Overcrowding the pan which lowers oil temperature and makes fish soggy","Skipping the paper towel drain step which leaves tacos greasy"]','["tacos","fish","seafood","quick","weeknight"]','["pescatarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Slow Cooker Pulled Pork','slow-cooker-pulled-pork','Tender smoky pork shoulder slow cooked all day in a rich spice rub and tangy barbecue sauce. It falls apart effortlessly and piles high onto soft buns.','Fall apart tender pork shoulder slow cooked with smoky spices and barbecue sauce.','American','Easy',15,480,495,8,510,42,28,22,1,'[{"amount":4,"unit":"lb","item":"boneless pork shoulder","group":"meat"},{"amount":2,"unit":"tbsp","item":"brown sugar","group":"rub"},{"amount":1,"unit":"tbsp","item":"smoked paprika","group":"rub"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"rub"},{"amount":1,"unit":"tsp","item":"onion powder","group":"rub"},{"amount":1,"unit":"tsp","item":"black pepper","group":"rub"},{"amount":1.5,"unit":"cups","item":"barbecue sauce","group":"sauce"},{"amount":0.5,"unit":"cup","item":"apple cider vinegar","group":"sauce"},{"amount":8,"unit":"pieces","item":"brioche buns","group":"serving"}]','[{"title":"Apply the Spice Rub","text":"Mix brown sugar smoked paprika garlic powder onion powder and black pepper in a bowl. Pat pork shoulder dry with paper towels then rub the spice mixture all over the meat.","timer":0},{"title":"Load the Slow Cooker","text":"Place the rubbed pork shoulder into the slow cooker. Pour apple cider vinegar and half of the barbecue sauce over the top.","timer":0},{"title":"Slow Cook","text":"Cook on low heat for 8 hours or on high heat for 5 hours. The pork is ready when it pulls apart easily with a fork.","timer":28800},{"title":"Shred the Pork","text":"Remove pork from the slow cooker and place on a cutting board. Use two forks to shred the meat completely. Discard any large pieces of fat.","timer":0},{"title":"Sauce and Serve","text":"Return shredded pork to the slow cooker and stir in the remaining barbecue sauce. Mix well and let sit for 5 minutes. Serve on toasted brioche buns.","timer":300}]','[{"original":"pork shoulder","swap":"pork butt or bone in pork shoulder"},{"original":"apple cider vinegar","swap":"white wine vinegar or orange juice"},{"original":"brioche buns","swap":"Hawaiian rolls or sandwich bread"}]','["Opening the slow cooker lid repeatedly which releases heat and extends cook time","Using pork loin instead of pork shoulder which results in dry stringy meat","Skipping the resting period before shredding which causes moisture loss"]','["pulled pork","slow cooker","barbecue","comfort food","meal prep"]','[]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hearty Beef Stew','hearty-beef-stew','Thick and warming beef stew loaded with tender chunks of chuck roast potatoes and carrots in a rich red wine broth. Perfect for cold nights and easy reheating.','Rich slow simmered beef stew with root vegetables in a deep savory broth.','American','Medium',20,120,140,6,480,36,32,18,5,'[{"amount":2,"unit":"lb","item":"beef chuck cut into 1 inch cubes","group":"meat"},{"amount":3,"unit":"pieces","item":"Yukon gold potatoes cubed","group":"vegetables"},{"amount":3,"unit":"pieces","item":"carrots sliced into rounds","group":"vegetables"},{"amount":1,"unit":"piece","item":"yellow onion diced","group":"vegetables"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":2,"unit":"tbsp","item":"tomato paste","group":"base"},{"amount":1,"unit":"cup","item":"dry red wine","group":"base"},{"amount":3,"unit":"cups","item":"beef broth","group":"base"},{"amount":2,"unit":"tbsp","item":"all purpose flour","group":"thickener"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"cooking"}]','[{"title":"Sear the Beef","text":"Pat beef cubes dry and season with salt and pepper. Toss with flour to coat. Heat olive oil in a large Dutch oven over high heat and sear beef in batches until browned on all sides. Do not crowd the pan. Remove and set aside.","timer":600},{"title":"Build the Base","text":"Reduce heat to medium and add onion and garlic to the same pot. Cook for 3 minutes until softened. Stir in tomato paste and cook for 1 more minute.","timer":240},{"title":"Deglaze and Simmer","text":"Pour in red wine and scrape up all the browned bits from the bottom of the pot. Add beef broth and return the seared beef to the pot. Bring to a boil then reduce to a gentle simmer.","timer":120},{"title":"Add Vegetables","text":"After 45 minutes of simmering add potatoes and carrots to the pot. Stir to combine and continue to simmer for another 45 minutes.","timer":5400},{"title":"Season and Serve","text":"Taste the stew and adjust seasoning with salt and pepper. The broth should be thick and the beef should be fork tender. Ladle into bowls and serve with crusty bread.","timer":0}]','[{"original":"beef chuck","swap":"beef brisket or short ribs"},{"original":"dry red wine","swap":"additional beef broth with a splash of Worcestershire sauce"},{"original":"Yukon gold potatoes","swap":"sweet potatoes or parsnips"}]','["Not searing the beef properly which skips the flavor building browning step","Adding vegetables too early which causes them to turn mushy before the beef is tender","Simmering at too high a heat which makes the beef tough instead of tender"]','["beef stew","comfort food","winter","one pot","slow cooked"]','[]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Chicken Alfredo','creamy-chicken-alfredo','Juicy pan seared chicken breast over silky fettuccine coated in a rich homemade Parmesan cream sauce. This classic Italian American dish comes together in just 30 minutes.','Tender chicken and fettuccine tossed in a velvety homemade Parmesan Alfredo sauce.','Italian American','Easy',10,25,35,4,680,44,52,32,2,'[{"amount":2,"unit":"pieces","item":"boneless skinless chicken breasts","group":"protein"},{"amount":12,"unit":"oz","item":"fettuccine pasta","group":"pasta"},{"amount":2,"unit":"tbsp","item":"butter","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":2,"unit":"cups","item":"heavy cream","group":"sauce"},{"amount":1.5,"unit":"cups","item":"freshly grated Parmesan cheese","group":"sauce"},{"amount":1,"unit":"tsp","item":"Italian seasoning","group":"seasoning"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":0.5,"unit":"cup","item":"pasta cooking water reserved","group":"sauce"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of heavily salted water to a boil. Cook fettuccine according to package instructions until al dente. Reserve half a cup of pasta water before draining.","timer":600},{"title":"Sear the Chicken","text":"Season chicken breasts with Italian seasoning salt and pepper. Heat olive oil in a large skillet over medium high heat. Sear chicken for 6 to 7 minutes per side until golden and cooked through. Rest for 5 minutes then slice.","timer":840},{"title":"Make the Alfredo Sauce","text":"In the same skillet melt butter over medium heat. Add garlic and cook for 1 minute until fragrant. Pour in heavy cream and bring to a gentle simmer. Cook for 3 to 4 minutes until slightly thickened.","timer":300},{"title":"Add the Parmesan","text":"Remove skillet from heat and stir in Parmesan cheese until fully melted and smooth. If the sauce is too thick add reserved pasta water a little at a time to loosen it.","timer":0},{"title":"Toss and Plate","text":"Add drained fettuccine to the sauce and toss until every strand is coated. Plate the pasta and top with sliced chicken. Garnish with extra Parmesan and freshly cracked black pepper.","timer":0}]','[{"original":"heavy cream","swap":"half and half for a lighter sauce"},{"original":"fettuccine","swap":"linguine or pappardelle"},{"original":"chicken breast","swap":"chicken thighs or shrimp"}]','["Using pre shredded Parmesan which contains anti caking agents that prevent smooth melting","Adding Parmesan while the pan is on high heat which causes the cheese to clump and become grainy","Draining pasta without saving pasta water which is essential for adjusting sauce consistency"]','["pasta","chicken","alfredo","creamy","weeknight","Italian"]','[]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Greek Yogurt Parfait','greek-yogurt-parfait','Layers of thick creamy Greek yogurt fresh berries and crunchy granola make this parfait a beautiful and nutritious way to start the day. It takes just 5 minutes to assemble.','Creamy Greek yogurt layered with fresh berries honey and crunchy granola for a quick healthy breakfast.','American','Easy',5,0,5,2,310,18,42,8,4,'[{"amount":2,"unit":"cups","item":"plain full fat Greek yogurt","group":"base"},{"amount":1,"unit":"cup","item":"fresh strawberries sliced","group":"fruit"},{"amount":0.5,"unit":"cup","item":"fresh blueberries","group":"fruit"},{"amount":0.5,"unit":"cup","item":"fresh raspberries","group":"fruit"},{"amount":0.75,"unit":"cup","item":"granola","group":"crunch"},{"amount":2,"unit":"tbsp","item":"honey","group":"sweetener"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"flavoring"},{"amount":2,"unit":"tbsp","item":"chia seeds","group":"topping"}]','[{"title":"Flavor the Yogurt","text":"In a bowl stir vanilla extract into the Greek yogurt until well combined. This adds a gentle sweetness without extra sugar.","timer":0},{"title":"Prepare the Fruit","text":"Slice strawberries and gently rinse blueberries and raspberries. Pat dry with a paper towel so they do not water down the yogurt layers.","timer":0},{"title":"Build the First Layer","text":"Spoon half of the yogurt evenly into two glasses or bowls. Add a layer of mixed berries on top of the yogurt.","timer":0},{"title":"Add Granola and Repeat","text":"Sprinkle half the granola over the berry layer then repeat with the remaining yogurt and berries. Top with the rest of the granola.","timer":0},{"title":"Finish and Serve","text":"Drizzle honey over each parfait and sprinkle chia seeds on top. Serve immediately to keep the granola crunchy.","timer":0}]','[{"original":"Greek yogurt","swap":"coconut yogurt for a dairy free version"},{"original":"honey","swap":"maple syrup or agave nectar"},{"original":"fresh berries","swap":"frozen berries thawed and drained or sliced banana"}]','["Building the parfait too far in advance which causes the granola to become soggy","Using low fat yogurt which results in a watery thin texture that does not hold layers well","Not drying the berries before layering which releases excess liquid and makes the parfait watery"]','["breakfast","healthy","parfait","yogurt","no cook","quick"]','["vegetarian","gluten free option"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Vegan Buddha Bowl','vegan-buddha-bowl','A nourishing bowl packed with roasted vegetables, quinoa, and creamy tahini dressing. This colorful meal delivers balanced nutrition in every bite.','A vibrant bowl of roasted veggies and quinoa topped with golden tahini dressing.','American','Easy',15,25,40,2,520,18,64,22,12,'[{"amount":1,"unit":"cup","item":"dry quinoa","group":"base"},{"amount":1,"unit":"can","item":"chickpeas drained and rinsed","group":"protein"},{"amount":1,"unit":"medium","item":"sweet potato cubed","group":"vegetables"},{"amount":2,"unit":"cups","item":"baby spinach","group":"vegetables"},{"amount":1,"unit":"medium","item":"avocado sliced","group":"vegetables"},{"amount":3,"unit":"tablespoons","item":"tahini","group":"dressing"},{"amount":2,"unit":"tablespoons","item":"lemon juice","group":"dressing"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"dressing"},{"amount":1,"unit":"teaspoon","item":"smoked paprika","group":"spices"},{"amount":1,"unit":"clove","item":"garlic minced","group":"dressing"}]','[{"title":"Cook the Quinoa","text":"Rinse quinoa under cold water. Combine with 2 cups of water in a saucepan, bring to a boil, then reduce heat and simmer until water is absorbed.","timer":900},{"title":"Roast the Vegetables","text":"Preheat oven to 400F. Toss sweet potato cubes and chickpeas with olive oil and smoked paprika. Spread on a baking sheet and roast until golden and tender.","timer":1500},{"title":"Make the Dressing","text":"Whisk together tahini, lemon juice, minced garlic, and 2 to 3 tablespoons of water until smooth and pourable. Season with salt to taste.","timer":120},{"title":"Assemble the Bowl","text":"Divide cooked quinoa between two bowls. Arrange roasted sweet potato, chickpeas, baby spinach, and avocado slices over the quinoa.","timer":180},{"title":"Dress and Serve","text":"Drizzle tahini dressing generously over each bowl. Add optional toppings like sesame seeds or red pepper flakes and serve immediately.","timer":60}]','[{"original":"quinoa","swap":"brown rice or farro"},{"original":"sweet potato","swap":"butternut squash or beets"},{"original":"tahini","swap":"almond butter or sunflower seed butter"}]','["Do not skip rinsing the quinoa as it removes the bitter coating called saponin","Do not overcrowd the baking sheet or the vegetables will steam instead of roast","Do not dress the bowl too far in advance or the greens will wilt"]','["healthy","meal prep","gluten-free","high protein","bowl"]','["vegan","gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Vegan Mac and Cheese','vegan-mac-and-cheese','An ultra-creamy pasta dish made with a silky cashew and nutritional yeast sauce. You will not miss the dairy in this deeply satisfying comfort food classic.','Creamy cashew-based cheese sauce coats tender pasta for the ultimate vegan comfort meal.','American','Medium',20,20,40,4,580,20,72,24,5,'[{"amount":12,"unit":"ounces","item":"elbow macaroni","group":"pasta"},{"amount":1.5,"unit":"cups","item":"raw cashews soaked for 2 hours","group":"sauce"},{"amount":0.5,"unit":"cup","item":"nutritional yeast","group":"sauce"},{"amount":1,"unit":"cup","item":"unsweetened plant milk","group":"sauce"},{"amount":2,"unit":"tablespoons","item":"lemon juice","group":"sauce"},{"amount":1,"unit":"teaspoon","item":"garlic powder","group":"sauce"},{"amount":1,"unit":"teaspoon","item":"onion powder","group":"sauce"},{"amount":1,"unit":"teaspoon","item":"dijon mustard","group":"sauce"},{"amount":0.5,"unit":"teaspoon","item":"turmeric","group":"sauce"},{"amount":1,"unit":"teaspoon","item":"salt","group":"seasoning"}]','[{"title":"Soak the Cashews","text":"Place raw cashews in a bowl and cover with hot water. Soak for at least 2 hours or overnight for the creamiest results. Drain and rinse before using.","timer":7200},{"title":"Cook the Pasta","text":"Bring a large pot of salted water to a boil. Cook macaroni according to package directions until al dente. Reserve half a cup of pasta water then drain.","timer":600},{"title":"Blend the Sauce","text":"Add drained cashews, nutritional yeast, plant milk, lemon juice, garlic powder, onion powder, mustard, turmeric, and salt to a high-speed blender. Blend until completely smooth.","timer":180},{"title":"Heat the Sauce","text":"Pour the blended sauce into a large saucepan over medium heat. Stir constantly until the sauce thickens slightly, about 4 minutes. Add reserved pasta water to adjust consistency.","timer":240},{"title":"Combine and Serve","text":"Add the cooked pasta to the sauce and stir until every piece is evenly coated. Taste and adjust seasoning. Serve hot with a sprinkle of extra nutritional yeast or smoked paprika.","timer":120}]','[{"original":"raw cashews","swap":"silken tofu or sunflower seeds for nut-free option"},{"original":"elbow macaroni","swap":"any short pasta such as penne or shells"},{"original":"dijon mustard","swap":"yellow mustard or a pinch of mustard powder"}]','["Do not skip soaking the cashews or the sauce will be grainy and not fully smooth","Do not use sweetened plant milk as it will make the sauce taste off","Do not overcook the pasta since it will continue to absorb sauce after mixing"]','["comfort food","pasta","creamy","kid-friendly","weeknight dinner"]','["vegan","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Vegan Tacos','vegan-tacos','Smoky spiced lentil and walnut taco filling packed into warm tortillas with fresh toppings. These tacos are hearty enough to satisfy even the most dedicated meat eaters.','Bold spiced lentil walnut filling makes these vegan tacos completely irresistible.','Mexican','Easy',10,25,35,4,440,17,52,18,11,'[{"amount":1,"unit":"cup","item":"green or brown lentils rinsed","group":"filling"},{"amount":1,"unit":"cup","item":"raw walnuts roughly chopped","group":"filling"},{"amount":8,"unit":"small","item":"corn tortillas","group":"base"},{"amount":2,"unit":"teaspoons","item":"cumin","group":"spices"},{"amount":2,"unit":"teaspoons","item":"smoked paprika","group":"spices"},{"amount":1,"unit":"teaspoon","item":"chili powder","group":"spices"},{"amount":1,"unit":"medium","item":"avocado mashed","group":"toppings"},{"amount":1,"unit":"cup","item":"pico de gallo","group":"toppings"},{"amount":0.5,"unit":"cup","item":"shredded red cabbage","group":"toppings"},{"amount":2,"unit":"tablespoons","item":"lime juice","group":"seasoning"}]','[{"title":"Cook the Lentils","text":"Combine rinsed lentils with 2 cups of water in a pot. Bring to a boil then simmer over medium-low heat until tender and water is absorbed, about 18 to 20 minutes.","timer":1200},{"title":"Prepare the Walnut Crumble","text":"Pulse walnuts in a food processor until they resemble a coarse crumble. Do not over-process or they will become a paste. Combine with cooked lentils in a skillet.","timer":60},{"title":"Season the Filling","text":"Add cumin, smoked paprika, chili powder, lime juice, and a pinch of salt to the lentil walnut mixture. Cook over medium heat for 5 minutes, stirring frequently.","timer":300},{"title":"Warm the Tortillas","text":"Heat tortillas one at a time in a dry skillet over medium-high heat for about 30 seconds per side until warm and slightly charred at the edges.","timer":240},{"title":"Assemble and Serve","text":"Spoon filling onto warm tortillas. Top with mashed avocado, pico de gallo, and shredded red cabbage. Finish with an extra squeeze of lime and serve immediately.","timer":180}]','[{"original":"lentils","swap":"black beans or chickpeas for a quicker option"},{"original":"corn tortillas","swap":"flour tortillas or large lettuce leaves"},{"original":"pico de gallo","swap":"store-bought salsa or diced fresh tomatoes with cilantro"}]','["Do not skip the walnuts as they add essential texture and richness to the filling","Do not use wet or undercooked lentils or the filling will be mushy","Do not overfill the tacos or they will fall apart when you try to eat them"]','["tacos","Mexican","high fiber","weeknight dinner","meal prep"]','["vegan","dairy-free","gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Vegan Chickpea Curry','vegan-chickpea-curry','A rich and aromatic curry simmered with creamy coconut milk, tender chickpeas, and warming spices. This one-pot wonder comes together quickly and tastes even better the next day.','A fragrant coconut milk curry loaded with chickpeas and bold Indian-inspired spices.','Indian','Easy',10,30,40,4,490,16,58,22,13,'[{"amount":2,"unit":"cans","item":"chickpeas drained and rinsed","group":"protein"},{"amount":1,"unit":"can","item":"full-fat coconut milk","group":"sauce"},{"amount":1,"unit":"can","item":"diced tomatoes","group":"sauce"},{"amount":1,"unit":"large","item":"yellow onion diced","group":"aromatics"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":1,"unit":"tablespoon","item":"fresh ginger grated","group":"aromatics"},{"amount":2,"unit":"tablespoons","item":"curry powder","group":"spices"},{"amount":1,"unit":"teaspoon","item":"garam masala","group":"spices"},{"amount":2,"unit":"tablespoons","item":"coconut oil","group":"cooking"},{"amount":2,"unit":"cups","item":"baby spinach","group":"vegetables"}]','[{"title":"Saute the Aromatics","text":"Heat coconut oil in a large pot over medium heat. Add diced onion and cook until softened and golden, about 7 minutes. Add garlic and ginger and cook for another 2 minutes.","timer":540},{"title":"Toast the Spices","text":"Add curry powder and garam masala directly to the pot with the aromatics. Stir constantly for 1 to 2 minutes until fragrant. This step deepens the flavor significantly.","timer":120},{"title":"Build the Sauce","text":"Pour in the diced tomatoes and coconut milk. Stir well to combine everything into a smooth sauce. Bring to a gentle boil then reduce heat to a simmer.","timer":300},{"title":"Add Chickpeas and Simmer","text":"Add the drained chickpeas to the pot. Simmer uncovered over low heat for 15 minutes, stirring occasionally, until the sauce thickens and flavors meld together.","timer":900},{"title":"Finish and Serve","text":"Stir in baby spinach and cook until wilted, about 2 minutes. Taste and adjust salt. Serve over steamed basmati rice or with warm naan bread and a wedge of lemon.","timer":120}]','[{"original":"chickpeas","swap":"lentils or cubed tofu for variety"},{"original":"full-fat coconut milk","swap":"light coconut milk for fewer calories"},{"original":"baby spinach","swap":"kale or frozen peas"}]','["Do not skip toasting the spices as this step unlocks their full depth of flavor","Do not use light coconut milk if you want a rich and creamy sauce","Do not rush the simmering time as the sauce needs time to reduce and thicken properly"]','["curry","Indian","one pot","meal prep","comfort food"]','["vegan","gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Vegan Chocolate Cake','vegan-chocolate-cake','A deeply moist and fudgy chocolate cake made without eggs or dairy. Topped with silky vegan chocolate ganache, this cake is completely indulgent and crowd-pleasing.','A rich fudgy chocolate cake with glossy ganache that happens to be completely vegan.','American','Medium',20,35,55,10,420,5,62,18,4,'[{"amount":2,"unit":"cups","item":"all-purpose flour","group":"dry"},{"amount":1.75,"unit":"cups","item":"granulated sugar","group":"dry"},{"amount":0.75,"unit":"cup","item":"unsweetened cocoa powder","group":"dry"},{"amount":2,"unit":"teaspoons","item":"baking soda","group":"dry"},{"amount":1,"unit":"cup","item":"unsweetened almond milk","group":"wet"},{"amount":1,"unit":"cup","item":"strong brewed coffee cooled","group":"wet"},{"amount":0.5,"unit":"cup","item":"neutral oil such as sunflower or canola","group":"wet"},{"amount":2,"unit":"tablespoons","item":"apple cider vinegar","group":"wet"},{"amount":1,"unit":"teaspoon","item":"pure vanilla extract","group":"wet"},{"amount":1,"unit":"cup","item":"vegan dark chocolate chips for ganache","group":"frosting"}]','[{"title":"Prepare the Batter","text":"Preheat oven to 350F and grease two 9-inch round cake pans. In a large bowl whisk together flour, sugar, cocoa powder, baking soda, and a half teaspoon of salt.","timer":300},{"title":"Mix Wet Ingredients","text":"In a separate bowl combine almond milk, cooled coffee, oil, apple cider vinegar, and vanilla extract. Whisk until fully combined. The vinegar activates the baking soda for lift.","timer":120},{"title":"Combine and Bake","text":"Pour the wet ingredients into the dry ingredients and stir until just combined. Do not overmix. Divide batter evenly between the prepared pans and bake for 30 to 35 minutes.","timer":2100},{"title":"Make the Ganache","text":"Heat half a cup of full-fat coconut cream until just simmering. Pour over the vegan chocolate chips in a bowl. Let sit for 2 minutes then stir until completely smooth and glossy.","timer":300},{"title":"Cool and Frost","text":"Let cakes cool completely in the pans before removing. Place one layer on a serving plate, spread ganache on top, then add the second layer and pour remaining ganache over the top.","timer":3600}]','[{"original":"almond milk","swap":"oat milk or soy milk for a nut-free version"},{"original":"brewed coffee","swap":"warm water for a milder chocolate flavor"},{"original":"apple cider vinegar","swap":"white wine vinegar or lemon juice"}]','["Do not overmix the batter or the cake will become dense and tough","Do not frost the cake while it is still warm or the ganache will melt and slide off","Do not skip the coffee as it deepens the chocolate flavor without making the cake taste like coffee"]','["chocolate","cake","dessert","birthday","baking"]','["vegan","dairy-free"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Vegan Vegetable Stir Fry','vegan-vegetable-stir-fry','A vibrant and colorful stir fry packed with fresh vegetables and a savory soy ginger sauce. This quick weeknight meal comes together in under 30 minutes.','A fast and flavorful vegan stir fry with crispy vegetables in a bold soy ginger sauce.','Asian','Easy',10,15,25,4,280,9,38,10,6,'[{"amount":2,"unit":"cups","item":"broccoli florets","group":"vegetables"},{"amount":1,"unit":"cup","item":"sliced bell peppers","group":"vegetables"},{"amount":1,"unit":"cup","item":"snap peas","group":"vegetables"},{"amount":1,"unit":"cup","item":"sliced carrots","group":"vegetables"},{"amount":3,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":1,"unit":"tbsp","item":"fresh grated ginger","group":"sauce"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":2,"unit":"tbsp","item":"sesame oil","group":"oil"},{"amount":1,"unit":"tbsp","item":"cornstarch","group":"sauce"},{"amount":2,"unit":"cups","item":"cooked jasmine rice","group":"base"}]','[{"title":"Prepare the Sauce","text":"In a small bowl whisk together soy sauce, grated ginger, minced garlic, cornstarch, and 2 tablespoons of water until smooth. Set aside.","timer":0},{"title":"Heat the Wok","text":"Heat sesame oil in a large wok or skillet over high heat until the oil begins to shimmer and is very hot.","timer":60},{"title":"Cook the Vegetables","text":"Add carrots and broccoli first and stir fry for 3 minutes. Add bell peppers and snap peas and continue cooking for another 2 minutes until vegetables are tender but still crisp.","timer":300},{"title":"Add the Sauce","text":"Pour the prepared sauce over the vegetables and toss everything together. Cook for 1 to 2 minutes until the sauce thickens and coats all the vegetables evenly.","timer":120},{"title":"Serve","text":"Serve immediately over cooked jasmine rice. Garnish with sesame seeds or sliced green onions if desired.","timer":0}]','[{"original":"soy sauce","swap":"tamari or coconut aminos for a gluten free option"},{"original":"sesame oil","swap":"avocado oil or vegetable oil"},{"original":"jasmine rice","swap":"brown rice, quinoa, or rice noodles"}]','["Do not overcrowd the wok as this causes steaming instead of stir frying","Do not use low heat as high heat is essential for proper caramelization","Do not skip the cornstarch as it is what makes the sauce thick and glossy"]','["stir fry","vegan","quick","weeknight","asian","healthy","gluten free option"]','["vegan","vegetarian","dairy free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Ultimate Vegan Black Bean Burger','ultimate-vegan-black-bean-burger','A hearty and satisfying vegan burger made with seasoned black beans, oats, and smoky spices. These patties hold together beautifully and pack a serious flavor punch.','Smoky and satisfying black bean burgers that are crispy on the outside and tender on the inside.','American','Medium',15,20,35,4,420,18,58,12,12,'[{"amount":2,"unit":"cans","item":"black beans drained and rinsed","group":"base"},{"amount":1,"unit":"cup","item":"rolled oats","group":"base"},{"amount":0.5,"unit":"cup","item":"diced red onion","group":"vegetables"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":2,"unit":"tsp","item":"smoked paprika","group":"spices"},{"amount":1,"unit":"tsp","item":"cumin","group":"spices"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"oil"},{"amount":4,"unit":"whole","item":"burger buns","group":"serving"},{"amount":1,"unit":"tbsp","item":"tomato paste","group":"seasoning"}]','[{"title":"Prepare the Beans","text":"Spread drained black beans on a baking sheet and bake at 375F for 10 minutes to dry them out slightly. This step prevents soggy patties.","timer":600},{"title":"Mix the Patty Base","text":"Transfer warm beans to a large bowl and mash about two thirds of them with a fork. Add rolled oats, diced red onion, garlic, smoked paprika, cumin, soy sauce, and tomato paste. Mix until combined.","timer":0},{"title":"Form the Patties","text":"Divide the mixture into 4 equal portions and shape each into a firm round patty about 3 quarters of an inch thick. Refrigerate for 10 minutes to help them hold their shape.","timer":600},{"title":"Cook the Patties","text":"Heat olive oil in a skillet over medium high heat. Cook each patty for 4 to 5 minutes per side until a dark crust forms. Do not move the patties until they release naturally from the pan.","timer":480},{"title":"Assemble and Serve","text":"Place cooked patties on toasted buns and top with your favorite vegan toppings such as lettuce, tomato, avocado, and vegan mayo.","timer":0}]','[{"original":"black beans","swap":"chickpeas or kidney beans work equally well"},{"original":"rolled oats","swap":"breadcrumbs or cooked quinoa for binding"},{"original":"soy sauce","swap":"tamari or liquid aminos for gluten free version"}]','["Do not skip drying the beans as excess moisture will cause the patties to fall apart","Do not flip the patties too early as they need time to form a crust before releasing","Do not make the patties too thick as the center will remain cold while the outside burns"]','["burger","vegan","black bean","american","bbq","grillable","high protein"]','["vegan","vegetarian","dairy free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Vegan Tomato Lentil Soup','creamy-vegan-tomato-lentil-soup','A rich and warming vegan soup made with red lentils, fire roasted tomatoes, and coconut milk. This comforting bowl is deeply nourishing and full of plant based protein.','A creamy and hearty tomato lentil soup that is deeply satisfying and easy to make.','Mediterranean','Easy',10,30,40,6,320,14,42,10,11,'[{"amount":1.5,"unit":"cups","item":"red lentils rinsed","group":"base"},{"amount":1,"unit":"can","item":"fire roasted crushed tomatoes","group":"base"},{"amount":1,"unit":"can","item":"full fat coconut milk","group":"base"},{"amount":1,"unit":"whole","item":"yellow onion diced","group":"vegetables"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":2,"unit":"tsp","item":"ground cumin","group":"spices"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"spices"},{"amount":4,"unit":"cups","item":"vegetable broth","group":"liquid"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"oil"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"}]','[{"title":"Saute the Aromatics","text":"Heat olive oil in a large pot over medium heat. Add diced onion and cook for 5 minutes until softened. Add garlic, cumin, and smoked paprika and cook for 1 more minute until fragrant.","timer":360},{"title":"Add the Base Ingredients","text":"Pour in the crushed tomatoes, rinsed red lentils, and vegetable broth. Stir to combine and bring the mixture to a boil.","timer":300},{"title":"Simmer the Soup","text":"Reduce heat to low and simmer uncovered for 20 minutes stirring occasionally until the lentils are completely soft and beginning to break down.","timer":1200},{"title":"Add Coconut Milk","text":"Stir in the coconut milk and season with salt. Use an immersion blender to partially blend the soup for a creamy texture while still leaving some chunks.","timer":60},{"title":"Serve","text":"Ladle the soup into bowls and garnish with a drizzle of coconut milk, fresh cilantro, and a squeeze of lemon juice for brightness.","timer":0}]','[{"original":"red lentils","swap":"green lentils work but require longer cooking time"},{"original":"full fat coconut milk","swap":"light coconut milk or cashew cream for lower fat option"},{"original":"fire roasted tomatoes","swap":"regular crushed tomatoes plus a pinch of extra smoked paprika"}]','["Do not skip rinsing the lentils as it removes excess starch and prevents a gummy texture","Do not boil the soup after adding coconut milk as it can cause the milk to separate","Do not blend the entire soup as leaving some texture makes it more satisfying and hearty"]','["soup","vegan","lentil","tomato","comfort food","high fiber","meal prep"]','["vegan","vegetarian","dairy free","gluten free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Vegan Creamy Cashew Pasta','vegan-creamy-cashew-pasta','A luxuriously creamy vegan pasta made with a silky cashew based sauce that rivals any dairy version. Tossed with garlic, nutritional yeast, and fresh herbs for a deeply satisfying meal.','Ultra creamy vegan pasta with a rich cashew sauce that tastes indulgent and comes together quickly.','Italian','Medium',15,20,35,4,520,17,68,20,5,'[{"amount":12,"unit":"oz","item":"fettuccine pasta","group":"base"},{"amount":1,"unit":"cup","item":"raw cashews soaked for 2 hours","group":"sauce"},{"amount":3,"unit":"tbsp","item":"nutritional yeast","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":1,"unit":"cup","item":"pasta cooking water","group":"liquid"},{"amount":1,"unit":"tbsp","item":"lemon juice","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"oil"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":0.25,"unit":"cup","item":"fresh basil leaves","group":"garnish"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of salted water to a boil and cook fettuccine according to package instructions until al dente. Reserve 1 cup of pasta cooking water before draining.","timer":600},{"title":"Blend the Cashew Sauce","text":"Drain the soaked cashews and add them to a blender with nutritional yeast, lemon juice, salt, pepper, and half a cup of the reserved pasta water. Blend on high for 2 minutes until completely smooth.","timer":120},{"title":"Saute the Garlic","text":"Heat olive oil in a large pan over medium heat. Add minced garlic and cook for 2 minutes until golden and fragrant. Do not let it burn.","timer":120},{"title":"Combine Everything","text":"Pour the blended cashew sauce into the pan with garlic. Add the drained pasta and toss to coat. Add more pasta water a splash at a time until the sauce reaches your desired consistency.","timer":120},{"title":"Finish and Serve","text":"Remove from heat and toss in fresh basil leaves. Taste and adjust seasoning. Serve immediately with extra nutritional yeast and black pepper on top.","timer":0}]','[{"original":"raw cashews","swap":"silken tofu blended smooth for a lower fat and nut free option"},{"original":"fettuccine","swap":"any pasta shape works especially linguine or penne"},{"original":"nutritional yeast","swap":"white miso paste for a different but equally savory flavor"}]','["Do not skip soaking the cashews as unsoaked cashews will result in a grainy sauce instead of smooth","Do not discard the pasta water as the starch in it is essential for making the sauce cling to the noodles","Do not overcook the garlic as burnt garlic will make the entire dish taste bitter"]','["pasta","vegan","creamy","cashew","italian","comfort food","date night"]','["vegan","vegetarian","dairy free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Fluffy Vegan Banana Oat Pancakes','fluffy-vegan-banana-oat-pancakes','Light and fluffy vegan pancakes made with ripe banana, oat flour, and flaxseed for binding. These wholesome pancakes are naturally sweet and ready in under 25 minutes.','Naturally sweetened vegan pancakes that are fluffy golden and packed with wholesome ingredients.','American','Easy',10,15,25,4,310,8,52,8,5,'[{"amount":2,"unit":"whole","item":"ripe bananas mashed","group":"base"},{"amount":1.5,"unit":"cups","item":"oat flour","group":"base"},{"amount":1,"unit":"cup","item":"unsweetened almond milk","group":"liquid"},{"amount":1,"unit":"tbsp","item":"ground flaxseed","group":"binder"},{"amount":3,"unit":"tbsp","item":"water","group":"binder"},{"amount":1,"unit":"tsp","item":"baking powder","group":"leavening"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"flavoring"},{"amount":0.5,"unit":"tsp","item":"cinnamon","group":"spices"},{"amount":1,"unit":"tbsp","item":"maple syrup","group":"sweetener"},{"amount":1,"unit":"tbsp","item":"coconut oil for cooking","group":"oil"}]','[{"title":"Make the Flax Egg","text":"Combine ground flaxseed with 3 tablespoons of water in a small bowl. Stir and let it sit for 5 minutes until it becomes gel like. This acts as your egg replacement.","timer":300},{"title":"Mix the Wet Ingredients","text":"In a large bowl mash the bananas until smooth. Add almond milk, vanilla extract, maple syrup, and the prepared flax egg. Whisk everything together until combined.","timer":0},{"title":"Add Dry Ingredients","text":"Add oat flour, baking powder, and cinnamon to the wet ingredients. Stir gently until just combined. Do not overmix as this will make the pancakes dense and tough.","timer":0},{"title":"Cook the Pancakes","text":"Heat coconut oil in a non stick pan over medium low heat. Pour about a quarter cup of batter per pancake. Cook for 3 to 4 minutes until bubbles form on the surface then flip and cook 2 more minutes.","timer":360},{"title":"Serve","text":"Stack the pancakes and serve immediately with fresh berries, sliced banana, and a generous drizzle of maple syrup. These are best enjoyed fresh off the pan.","timer":0}]','[{"original":"oat flour","swap":"whole wheat flour or all purpose flour in the same quantity"},{"original":"almond milk","swap":"oat milk, soy milk, or any other plant based milk"},{"original":"ground flaxseed","swap":"chia seeds mixed with water in the same ratio for binding"}]','["Do not overmix the batter as gluten development from overmixing results in rubbery and flat pancakes","Do not cook on high heat as vegan pancakes need lower heat to cook through without burning","Do not flip the pancakes too early as waiting for bubbles to form on the surface ensures they are ready"]','["pancakes","vegan","breakfast","banana","oat","gluten free option","kid friendly"]','["vegan","vegetarian","dairy free","egg free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Keto Pizza','keto-pizza','A crispy fathead dough pizza loaded with melted mozzarella and savory toppings. This low-carb pizza satisfies every craving without the guilt.','A cheesy fathead crust pizza ready in under 30 minutes.','Italian','Medium',15,15,30,4,420,28,6,32,1,'[{"amount":1.5,"unit":"cup","item":"shredded mozzarella cheese","group":"crust"},{"amount":2,"unit":"tbsp","item":"cream cheese","group":"crust"},{"amount":0.75,"unit":"cup","item":"almond flour","group":"crust"},{"amount":1,"unit":"whole","item":"large egg","group":"crust"},{"amount":0.5,"unit":"tsp","item":"garlic powder","group":"crust"},{"amount":0.5,"unit":"cup","item":"low carb marinara sauce","group":"topping"},{"amount":1,"unit":"cup","item":"shredded mozzarella cheese","group":"topping"},{"amount":0.5,"unit":"cup","item":"sliced pepperoni","group":"topping"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"topping"}]','[{"title":"Melt the Cheeses","text":"Combine 1.5 cups mozzarella and cream cheese in a microwave-safe bowl. Microwave for 90 seconds, stirring halfway through, until fully melted and combined.","timer":90},{"title":"Form the Dough","text":"Add almond flour, egg, and garlic powder to the melted cheese mixture. Mix vigorously until a uniform dough forms. If the dough cools and becomes stiff, microwave for 20 seconds.","timer":0},{"title":"Press and Pre-bake the Crust","text":"Preheat oven to 425F. Press the dough into a circle on parchment-lined baking sheet. Poke holes with a fork across the surface. Bake for 8 minutes until lightly golden.","timer":480},{"title":"Add Toppings","text":"Spread marinara sauce evenly over the pre-baked crust. Top with shredded mozzarella, pepperoni slices, and dried oregano.","timer":0},{"title":"Final Bake","text":"Return pizza to oven and bake for an additional 7 minutes until the cheese is bubbly and golden. Let cool for 2 minutes before slicing.","timer":420}]','[{"original":"almond flour","swap":"sunflower seed flour for nut-free version"},{"original":"pepperoni","swap":"cooked Italian sausage crumbles"},{"original":"low carb marinara","swap":"pesto sauce for a white pizza"}]','["Do not skip pre-baking the crust or it will be soggy under the toppings","Do not overheat the cheese mixture or it will become rubbery and hard to mix","Do not use too much sauce or the crust will lose its crispiness"]','["keto","low-carb","fathead dough","pizza","gluten-free"]','["keto","gluten-free","low-carb"]','Main Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Keto Bread','keto-bread','A fluffy almond flour sandwich bread with a tender crumb and golden crust. This keto bread slices perfectly and works great for sandwiches and toast.','A simple almond flour loaf that tastes like real sandwich bread.','American','Easy',10,30,40,12,180,7,4,15,2,'[{"amount":2,"unit":"cup","item":"blanched almond flour","group":"dry"},{"amount":0.25,"unit":"cup","item":"psyllium husk powder","group":"dry"},{"amount":1,"unit":"tsp","item":"baking powder","group":"dry"},{"amount":0.5,"unit":"tsp","item":"salt","group":"dry"},{"amount":4,"unit":"whole","item":"large eggs","group":"wet"},{"amount":0.25,"unit":"cup","item":"melted butter","group":"wet"},{"amount":0.25,"unit":"cup","item":"sour cream","group":"wet"},{"amount":1,"unit":"tsp","item":"apple cider vinegar","group":"wet"}]','[{"title":"Preheat and Prepare Pan","text":"Preheat oven to 350F. Grease a standard 9x5 inch loaf pan with butter or line with parchment paper. Set aside.","timer":0},{"title":"Mix Dry Ingredients","text":"In a large bowl, whisk together almond flour, psyllium husk powder, baking powder, and salt until evenly combined and free of lumps.","timer":0},{"title":"Combine Wet Ingredients","text":"In a separate bowl, whisk eggs, melted butter, sour cream, and apple cider vinegar together until smooth and well combined.","timer":0},{"title":"Mix and Transfer","text":"Pour the wet ingredients into the dry ingredients and stir until a thick, uniform batter forms. Transfer batter into the prepared loaf pan and smooth the top with a spatula.","timer":0},{"title":"Bake the Bread","text":"Bake for 30 minutes until the top is golden brown and a toothpick inserted in the center comes out clean. Let cool in pan for 10 minutes before slicing.","timer":1800}]','[{"original":"sour cream","swap":"full-fat Greek yogurt for similar moisture"},{"original":"butter","swap":"coconut oil for a dairy-free option"},{"original":"psyllium husk powder","swap":"ground flaxseed for added omega-3s"}]','["Do not use coarse almond flour as it will produce a gritty dense loaf","Do not slice the bread before it has cooled or it will crumble apart","Do not skip the apple cider vinegar as it helps the bread rise properly"]','["keto","low-carb","bread","gluten-free","meal prep"]','["keto","gluten-free","low-carb","vegetarian"]','Bread','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Keto Brownies','keto-brownies','Rich fudgy chocolate brownies made with almond flour and sweetened with erythritol. These indulgent squares taste just like the real thing with almost no carbs.','Fudgy chocolate brownies that are completely sugar-free and low-carb.','American','Easy',10,25,35,9,210,5,5,19,3,'[{"amount":0.5,"unit":"cup","item":"unsalted butter","group":"wet"},{"amount":2,"unit":"oz","item":"unsweetened dark chocolate","group":"wet"},{"amount":0.75,"unit":"cup","item":"granular erythritol","group":"dry"},{"amount":2,"unit":"whole","item":"large eggs","group":"wet"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"wet"},{"amount":0.5,"unit":"cup","item":"blanched almond flour","group":"dry"},{"amount":0.25,"unit":"cup","item":"unsweetened cocoa powder","group":"dry"},{"amount":0.25,"unit":"tsp","item":"salt","group":"dry"},{"amount":0.25,"unit":"cup","item":"sugar-free chocolate chips","group":"mix-in"}]','[{"title":"Melt Butter and Chocolate","text":"Preheat oven to 350F and line an 8x8 inch baking pan with parchment. Melt butter and dark chocolate together in a microwave in 30-second intervals, stirring between each until smooth.","timer":60},{"title":"Add Sweetener and Eggs","text":"Whisk erythritol into the warm chocolate mixture until dissolved. Add eggs one at a time, whisking well after each addition. Stir in vanilla extract.","timer":0},{"title":"Fold in Dry Ingredients","text":"Sift almond flour, cocoa powder, and salt directly into the chocolate mixture. Fold gently with a spatula until just combined. Do not overmix.","timer":0},{"title":"Add Chips and Pour","text":"Fold in sugar-free chocolate chips, then pour the batter into the prepared pan. Spread evenly to the edges with a spatula.","timer":0},{"title":"Bake and Cool","text":"Bake for 22 to 25 minutes until the center is just set and a toothpick comes out with moist crumbs. Cool completely in the pan before cutting into 9 squares.","timer":1500}]','[{"original":"erythritol","swap":"monk fruit sweetener in equal amounts"},{"original":"almond flour","swap":"sunflower seed flour for nut-free version"},{"original":"unsalted butter","swap":"coconut oil for a dairy-free brownie"}]','["Do not overbake the brownies or they will dry out and lose their fudgy texture","Do not cut brownies while warm as they will fall apart before setting","Do not substitute allulose for erythritol as the bake time and texture will change significantly"]','["keto","low-carb","dessert","chocolate","sugar-free","gluten-free"]','["keto","gluten-free","low-carb","sugar-free","vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Keto Chicken Thighs','keto-chicken-thighs','Crispy skin-on chicken thighs roasted with garlic butter and herbs until perfectly golden. This easy weeknight dinner is juicy, flavorful, and naturally zero-carb.','Juicy garlic butter roasted chicken thighs with irresistibly crispy skin.','American','Easy',10,35,45,4,390,32,1,28,0,'[{"amount":4,"unit":"whole","item":"bone-in skin-on chicken thighs","group":"protein"},{"amount":3,"unit":"tbsp","item":"unsalted butter softened","group":"sauce"},{"amount":4,"unit":"clove","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":1,"unit":"tsp","item":"dried thyme","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"onion powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"cooking"}]','[{"title":"Prepare the Chicken","text":"Preheat oven to 425F. Pat chicken thighs completely dry with paper towels. Drying the skin is essential for maximum crispiness.","timer":0},{"title":"Make Garlic Butter","text":"Mix softened butter, minced garlic, smoked paprika, thyme, onion powder, salt, and pepper in a small bowl until fully combined into a smooth compound butter.","timer":0},{"title":"Season the Chicken","text":"Rub olive oil over each chicken thigh, then massage the garlic butter mixture under and over the skin, coating each thigh generously.","timer":0},{"title":"Roast the Chicken","text":"Place chicken thighs skin-side up in an oven-safe skillet or baking dish. Roast at 425F for 35 minutes until the skin is deep golden brown and crispy.","timer":2100},{"title":"Rest and Serve","text":"Check internal temperature reaches 165F with a meat thermometer. Let chicken rest for 5 minutes before serving to allow juices to redistribute.","timer":300}]','[{"original":"butter","swap":"ghee for a higher smoke point and dairy-light option"},{"original":"smoked paprika","swap":"regular paprika plus a pinch of cumin"},{"original":"dried thyme","swap":"fresh rosemary for a more aromatic herb flavor"}]','["Do not skip patting the chicken dry as moisture is the enemy of crispy skin","Do not cover the pan while roasting as steam will prevent the skin from crisping","Do not move or flip the thighs during cooking as the skin needs direct dry heat to crisp up"]','["keto","low-carb","chicken","weeknight dinner","gluten-free","zero-carb"]','["keto","gluten-free","low-carb","dairy-free adaptable"]','Main Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Keto Salmon','keto-salmon','Pan-seared salmon fillets with a lemon herb butter sauce that comes together in just 20 minutes. This omega-3 rich dish is elegant enough for company and easy enough for any weeknight.','Perfectly seared salmon in a bright lemon herb butter sauce ready in 20 minutes.','American','Easy',5,15,20,4,380,34,2,26,0,'[{"amount":4,"unit":"whole","item":"salmon fillets skin-on","group":"protein"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":3,"unit":"clove","item":"garlic minced","group":"sauce"},{"amount":2,"unit":"tbsp","item":"fresh lemon juice","group":"sauce"},{"amount":1,"unit":"tsp","item":"lemon zest","group":"sauce"},{"amount":2,"unit":"tbsp","item":"fresh dill chopped","group":"herb"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"}]','[{"title":"Prep the Salmon","text":"Pat salmon fillets completely dry with paper towels. Season both sides generously with salt and black pepper. Let sit at room temperature for 5 minutes.","timer":300},{"title":"Heat the Pan","text":"Heat olive oil in a large stainless steel or cast iron skillet over medium-high heat until the oil shimmers and just begins to smoke.","timer":120},{"title":"Sear the Salmon","text":"Place salmon skin-side up in the hot pan. Cook undisturbed for 4 minutes until a golden crust forms. Flip carefully and cook skin-side down for 3 to 4 more minutes.","timer":480},{"title":"Make the Lemon Herb Butter","text":"Reduce heat to medium-low. Add butter and garlic to the pan. Cook for 1 minute until fragrant, then stir in lemon juice and lemon zest. Spoon sauce over the salmon repeatedly for 1 minute.","timer":120},{"title":"Finish and Serve","text":"Remove salmon from heat and sprinkle with fresh dill. Spoon remaining pan sauce over each fillet. Serve immediately with lemon wedges on the side.","timer":0}]','[{"original":"fresh dill","swap":"fresh parsley or chives for a milder herb flavor"},{"original":"butter","swap":"coconut oil for a fully dairy-free preparation"},{"original":"lemon juice","swap":"lime juice for a slightly different citrus profile"}]','["Do not move the salmon in the pan before the crust forms or it will stick and tear","Do not cook salmon straight from the refrigerator as cold fish cooks unevenly","Do not overcook the salmon as it should still be slightly translucent in the very center"]','["keto","low-carb","salmon","seafood","gluten-free","quick dinner"]','["keto","gluten-free","low-carb","pescatarian"]','Main Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Keto Cauliflower Mash','keto-cauliflower-mash','A creamy low-carb alternative to mashed potatoes made with cauliflower and rich butter. This dish delivers comfort food satisfaction without the carb overload.','Silky smooth cauliflower mash loaded with butter and cream cheese for the ultimate keto side dish.','American','Easy',10,15,25,4,180,5,7,15,3,'[{"amount":1,"unit":"head","item":"cauliflower cut into florets","group":"main"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"main"},{"amount":2,"unit":"oz","item":"cream cheese softened","group":"main"},{"amount":0.25,"unit":"cup","item":"heavy cream","group":"main"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh chives chopped","group":"garnish"}]','[{"title":"Boil the Cauliflower","text":"Bring a large pot of salted water to a boil. Add cauliflower florets and cook until very tender, about 10 to 12 minutes. Do not undercook or the mash will be lumpy.","timer":720},{"title":"Drain and Dry","text":"Drain the cauliflower thoroughly in a colander. Return it to the hot pot and let it sit for 2 minutes over low heat to evaporate excess moisture. This step is critical for a thick mash.","timer":120},{"title":"Blend with Fats","text":"Transfer the cauliflower to a food processor. Add butter, cream cheese, heavy cream, and garlic. Process until completely smooth and creamy, scraping down the sides as needed.","timer":60},{"title":"Season and Adjust","text":"Taste the mash and add salt and black pepper. Pulse a few more times to incorporate. Adjust cream or butter for desired consistency.","timer":30},{"title":"Serve and Garnish","text":"Transfer to a serving bowl and top with fresh chives and an optional pat of butter. Serve immediately while hot.","timer":0}]','[{"original":"heavy cream","swap":"full fat coconut cream for dairy free version"},{"original":"cream cheese","swap":"mascarpone for a richer flavor"},{"original":"butter","swap":"ghee for a lactose free option"}]','["Not draining cauliflower well enough which results in watery mash","Undercooking the cauliflower which leads to a lumpy texture","Over processing the mash which can make it gluey"]','["keto","low-carb","side dish","vegetarian","comfort food"]','["keto","gluten-free","vegetarian"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Keto Egg Muffins','keto-egg-muffins','Portable and protein packed mini frittatas baked in a muffin tin with cheese and vegetables. These make the perfect grab and go keto breakfast for busy mornings.','Easy baked egg cups loaded with cheese, spinach, and bacon for a satisfying low-carb breakfast.','American','Easy',10,20,30,6,210,14,2,16,0,'[{"amount":8,"unit":"large","item":"eggs","group":"main"},{"amount":4,"unit":"strips","item":"bacon cooked and crumbled","group":"main"},{"amount":0.5,"unit":"cup","item":"shredded cheddar cheese","group":"main"},{"amount":1,"unit":"cup","item":"fresh spinach chopped","group":"vegetables"},{"amount":0.25,"unit":"cup","item":"diced red bell pepper","group":"vegetables"},{"amount":2,"unit":"tbsp","item":"heavy cream","group":"main"},{"amount":0.5,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"salt and black pepper","group":"seasoning"}]','[{"title":"Preheat and Prep Pan","text":"Preheat oven to 375 degrees Fahrenheit. Grease a 12 cup muffin tin generously with butter or cooking spray. Do not skip greasing or the muffins will stick badly.","timer":0},{"title":"Whisk the Egg Mixture","text":"Crack all eggs into a large bowl and add heavy cream, garlic powder, salt, and pepper. Whisk vigorously until fully combined and slightly frothy.","timer":60},{"title":"Add Fillings","text":"Stir in the crumbled bacon, shredded cheddar, chopped spinach, and diced bell pepper into the egg mixture. Mix well to distribute evenly.","timer":30},{"title":"Fill and Bake","text":"Pour the mixture evenly into the prepared muffin cups, filling each about three quarters full. Bake for 18 to 20 minutes until the eggs are set and tops are lightly golden.","timer":1200},{"title":"Cool and Remove","text":"Let the muffins cool in the pan for 5 minutes before running a knife around the edges and removing. Store leftovers in the refrigerator for up to 4 days.","timer":300}]','[{"original":"bacon","swap":"diced ham or cooked sausage crumbles"},{"original":"cheddar cheese","swap":"feta or goat cheese for a tangy flavor"},{"original":"spinach","swap":"kale or diced zucchini"}]','["Not greasing the muffin tin which causes the eggs to stick and tear","Overfilling the cups which causes overflow during baking","Removing muffins too soon before they have fully set in the center"]','["keto","low-carb","breakfast","meal prep","gluten-free"]','["keto","gluten-free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Keto Avocado Boats','keto-avocado-boats','Halved avocados filled with a savory tuna or egg salad mixture for a quick and satisfying keto meal. Each boat is rich in healthy fats and requires zero cooking.','Creamy avocado halves stuffed with herbed tuna salad for a fast no-cook keto lunch.','American','Easy',10,0,10,2,390,22,6,32,7,'[{"amount":2,"unit":"large","item":"ripe avocados halved and pitted","group":"main"},{"amount":2,"unit":"cans","item":"tuna in water drained","group":"main"},{"amount":3,"unit":"tbsp","item":"mayonnaise","group":"main"},{"amount":1,"unit":"stalk","item":"celery finely diced","group":"vegetables"},{"amount":1,"unit":"tbsp","item":"lemon juice","group":"seasoning"},{"amount":1,"unit":"tsp","item":"Dijon mustard","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"salt and black pepper","group":"seasoning"},{"amount":1,"unit":"tbsp","item":"fresh dill chopped","group":"garnish"}]','[{"title":"Prepare the Avocados","text":"Slice avocados in half lengthwise and remove the pits. Use a spoon to slightly enlarge the hollow where the pit was to create more room for filling.","timer":0},{"title":"Mix the Tuna Filling","text":"In a medium bowl, combine drained tuna, mayonnaise, diced celery, lemon juice, and Dijon mustard. Mix well until thoroughly combined.","timer":60},{"title":"Season the Filling","text":"Add salt, black pepper, and fresh dill to the tuna mixture. Taste and adjust seasoning as needed. The filling should be creamy and well seasoned.","timer":30},{"title":"Fill the Boats","text":"Spoon the tuna mixture generously into each avocado half, mounding it slightly above the surface. Do not be shy with the filling.","timer":0},{"title":"Garnish and Serve","text":"Top each boat with a sprig of fresh dill and a small squeeze of lemon juice. Serve immediately to prevent the avocado from browning.","timer":0}]','[{"original":"tuna","swap":"shredded rotisserie chicken or canned salmon"},{"original":"mayonnaise","swap":"mashed avocado for extra creaminess"},{"original":"celery","swap":"diced cucumber or red onion for crunch"}]','["Using underripe avocados which are hard and difficult to eat","Not draining tuna well enough which makes the filling watery","Preparing too far in advance causing the avocado to oxidize and turn brown"]','["keto","low-carb","no-cook","lunch","high-fat"]','["keto","gluten-free","dairy-free"]','Lunch','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Keto Steak Bites','keto-steak-bites','Juicy bite sized pieces of sirloin steak seared in a hot cast iron pan with garlic butter. These protein rich bites cook in under 10 minutes and are packed with bold flavor.','Tender pan seared steak bites finished in garlic herb butter for an irresistible keto dinner.','American','Medium',10,10,20,4,420,38,1,29,0,'[{"amount":1.5,"unit":"lbs","item":"sirloin steak cut into 1 inch cubes","group":"main"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"main"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"main"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"garnish"}]','[{"title":"Season the Steak","text":"Pat the steak cubes completely dry with paper towels. This is essential for getting a proper sear. Toss with smoked paprika, garlic powder, and salt until evenly coated.","timer":0},{"title":"Heat the Pan","text":"Heat a cast iron skillet over high heat until it is smoking hot. Add olive oil and let it shimmer. Do not use a non-stick pan as it cannot handle high enough heat for a proper sear.","timer":120},{"title":"Sear the Steak Bites","text":"Add the steak cubes in a single layer without overcrowding the pan. Sear for 2 minutes without moving them, then flip and sear for another 1 to 2 minutes for medium doneness.","timer":240},{"title":"Add the Garlic Butter","text":"Reduce heat to medium low. Add butter and minced garlic to the pan. Toss the steak bites continuously for 60 seconds as the butter melts and the garlic becomes fragrant.","timer":60},{"title":"Rest and Garnish","text":"Remove from heat and let the steak bites rest for 2 minutes before serving. Garnish with fresh parsley and spoon any remaining pan butter over the top.","timer":120}]','[{"original":"sirloin steak","swap":"ribeye or flank steak for different fat levels"},{"original":"butter","swap":"ghee for a higher smoke point"},{"original":"smoked paprika","swap":"cayenne pepper for extra heat"}]','["Not drying the steak before searing which causes steaming instead of browning","Overcrowding the pan which drops the temperature and prevents a proper crust","Moving the steak too early before a crust has formed on each side"]','["keto","low-carb","high-protein","dinner","quick meal"]','["keto","gluten-free","dairy-free option"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Keto Fat Bombs','keto-fat-bombs','Rich chocolate peanut butter fat bombs made with coconut oil and cream cheese to fuel your ketogenic diet. These no bake bites are perfect for satisfying sweet cravings while staying in ketosis.','Creamy chocolate peanut butter fat bombs that set firm in the freezer for an easy keto snack.','American','Easy',15,0,75,12,160,3,3,16,1,'[{"amount":4,"unit":"oz","item":"cream cheese softened","group":"main"},{"amount":0.5,"unit":"cup","item":"natural peanut butter no sugar added","group":"main"},{"amount":0.25,"unit":"cup","item":"refined coconut oil melted","group":"main"},{"amount":3,"unit":"tbsp","item":"unsweetened cocoa powder","group":"main"},{"amount":3,"unit":"tbsp","item":"powdered erythritol or monk fruit sweetener","group":"sweetener"},{"amount":1,"unit":"tsp","item":"pure vanilla extract","group":"flavoring"},{"amount":0.25,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"unsweetened shredded coconut for rolling","group":"topping"}]','[{"title":"Mix the Base","text":"In a medium bowl, beat softened cream cheese with a hand mixer until smooth. Add peanut butter and melted coconut oil and beat until fully combined and creamy.","timer":120},{"title":"Add Flavor and Sweetener","text":"Add cocoa powder, powdered sweetener, vanilla extract, and salt to the mixture. Beat on medium speed until everything is smooth and no lumps remain. Taste and adjust sweetness.","timer":60},{"title":"Chill the Mixture","text":"Place the bowl in the refrigerator for 20 to 30 minutes until the mixture is firm enough to scoop and roll into balls without sticking to your hands.","timer":1800},{"title":"Shape the Fat Bombs","text":"Using a tablespoon or small cookie scoop, portion the mixture and roll each portion between your palms into a smooth ball. Work quickly as the mixture softens from hand warmth.","timer":300},{"title":"Coat and Freeze","text":"Roll each ball in shredded coconut or leave plain. Place on a parchment lined tray and freeze for at least 30 minutes until solid. Store in the freezer for up to 3 weeks.","timer":1800}]','[{"original":"peanut butter","swap":"almond butter or sunflower seed butter for nut free version"},{"original":"erythritol","swap":"stevia drops adjusted to taste"},{"original":"coconut oil","swap":"extra cream cheese for a denser texture"}]','["Not chilling the mixture long enough which makes it impossible to roll into balls","Using regular peanut butter with added sugar which adds unnecessary carbs","Storing at room temperature which causes the fat bombs to melt and lose their shape"]','["keto","low-carb","snack","no-bake","dessert","meal prep"]','["keto","gluten-free","vegetarian"]','Snack','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Protein Pancakes','protein-pancakes','Fluffy high protein pancakes made with oats and cottage cheese for a nutritious breakfast. These pancakes deliver serious muscle fuel without sacrificing taste or texture.','High protein fluffy pancakes ready in 20 minutes using simple wholesome ingredients.','American','Easy',5,15,20,2,340,32,38,7,4,'[{"amount":1,"unit":"cup","item":"rolled oats","group":"base"},{"amount":1,"unit":"cup","item":"cottage cheese","group":"base"},{"amount":3,"unit":"whole","item":"eggs","group":"base"},{"amount":1,"unit":"scoop","item":"vanilla protein powder","group":"protein"},{"amount":1,"unit":"tsp","item":"baking powder","group":"leavening"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"flavoring"},{"amount":0.5,"unit":"tsp","item":"cinnamon","group":"flavoring"},{"amount":1,"unit":"tbsp","item":"honey","group":"sweetener"}]','[{"title":"Blend the batter","text":"Add oats, cottage cheese, eggs, protein powder, baking powder, vanilla extract, cinnamon and honey to a blender. Blend on high for 45 seconds until the batter is completely smooth and no oat chunks remain.","timer":45},{"title":"Rest the batter","text":"Let the batter rest for 3 minutes so the oats can absorb moisture and the baking powder activates. The batter should thicken slightly during this time.","timer":180},{"title":"Heat the pan","text":"Heat a non-stick skillet over medium-low heat. Lightly coat with cooking spray. The pan is ready when a drop of water sizzles gently on the surface.","timer":60},{"title":"Cook the pancakes","text":"Pour roughly one quarter cup of batter per pancake into the skillet. Cook until bubbles form across the surface and the edges look set, about 2 to 3 minutes. Flip once and cook for another 2 minutes until golden.","timer":300},{"title":"Serve immediately","text":"Stack the finished pancakes and top with fresh berries, a drizzle of honey or Greek yogurt. Serve hot for the best texture and flavor.","timer":0}]','[{"original":"cottage cheese","swap":"Greek yogurt for a tangier flavor"},{"original":"vanilla protein powder","swap":"unflavored whey protein plus extra vanilla extract"},{"original":"honey","swap":"maple syrup or mashed ripe banana"}]','["Cooking on heat that is too high which burns the outside before the inside is cooked through","Flipping the pancake too early before bubbles have formed on the surface","Skipping the resting step which results in a thin runny batter"]','["breakfast","high protein","meal prep","gluten free option","quick"]','["gluten-free adaptable","vegetarian"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Chicken Breast Meal Prep','chicken-breast-meal-prep','Juicy perfectly seasoned baked chicken breasts prepared in bulk for a full week of healthy meals. Simple prep and hands-off oven cooking make this the ultimate weekly staple.','Batch baked seasoned chicken breasts that stay moist and delicious all week long.','American','Easy',10,25,35,4,280,48,2,8,0,'[{"amount":4,"unit":"whole","item":"boneless skinless chicken breasts","group":"protein"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"fat"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"onion powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"}]','[{"title":"Preheat and prepare","text":"Preheat your oven to 425 degrees Fahrenheit. Line a large baking sheet with parchment paper or lightly grease it with cooking spray to prevent sticking.","timer":600},{"title":"Pound and season the chicken","text":"Place chicken breasts between two sheets of plastic wrap and pound to an even thickness of about three quarters of an inch. Rub each breast with olive oil then coat evenly with the combined spice mixture on all sides.","timer":0},{"title":"Arrange on baking sheet","text":"Place the seasoned chicken breasts on the prepared baking sheet with at least one inch of space between each piece. Do not stack or overlap them as this will cause steaming instead of roasting.","timer":0},{"title":"Bake until cooked through","text":"Bake in the preheated oven for 20 to 25 minutes until the internal temperature reaches 165 degrees Fahrenheit. Use a meat thermometer inserted into the thickest part for an accurate reading.","timer":1500},{"title":"Rest and store","text":"Remove from the oven and let the chicken rest on the pan for 5 minutes before slicing or storing. Divide into meal prep containers and refrigerate for up to 5 days.","timer":300}]','[{"original":"smoked paprika","swap":"regular paprika or chili powder for a different heat level"},{"original":"olive oil","swap":"avocado oil which handles high heat very well"},{"original":"dried oregano","swap":"Italian seasoning blend or dried thyme"}]','["Skipping the pounding step which causes uneven cooking with dry edges and raw centers","Not using a meat thermometer and relying on cook time alone which is unreliable","Cutting into the chicken immediately after baking which releases all the juices and dries it out"]','["meal prep","high protein","low carb","batch cooking","oven baked"]','["gluten-free","dairy-free","paleo","keto"]','Meal Prep','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Turkey Meatballs','turkey-meatballs','Tender and flavorful lean turkey meatballs seasoned with garlic, herbs and Parmesan cheese. They are lighter than traditional beef meatballs but packed with protein and satisfying flavor.','Lean turkey meatballs that are juicy, herby and perfect for pasta or meal prep.','Italian','Medium',15,20,35,4,290,34,8,13,1,'[{"amount":500,"unit":"g","item":"lean ground turkey","group":"protein"},{"amount":1,"unit":"whole","item":"egg","group":"binder"},{"amount":0.33,"unit":"cup","item":"breadcrumbs","group":"binder"},{"amount":0.25,"unit":"cup","item":"grated Parmesan cheese","group":"flavor"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"flavor"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"flavor"},{"amount":1,"unit":"tsp","item":"Italian seasoning","group":"seasoning"},{"amount":0.75,"unit":"tsp","item":"salt","group":"seasoning"}]','[{"title":"Mix the meatball mixture","text":"In a large bowl combine ground turkey, egg, breadcrumbs, Parmesan, garlic, parsley, Italian seasoning and salt. Use your hands or a fork to mix until just combined. Do not overmix or the meatballs will become tough and dense.","timer":0},{"title":"Form the meatballs","text":"Wet your hands with cold water to prevent sticking. Scoop roughly two tablespoons of mixture and roll gently between your palms to form smooth balls. Place them on a lined baking sheet and aim for uniform size so they cook evenly.","timer":0},{"title":"Preheat and prepare oven","text":"Preheat the oven to 400 degrees Fahrenheit. Lightly spray the lined baking sheet with cooking spray. Space the meatballs at least half an inch apart so they brown properly rather than steam.","timer":600},{"title":"Bake the meatballs","text":"Bake for 18 to 20 minutes until the meatballs are golden brown on the outside and reach an internal temperature of 165 degrees Fahrenheit. They will firm up as they cool slightly.","timer":1200},{"title":"Serve or store","text":"Serve immediately over pasta with marinara sauce or let cool completely before storing in an airtight container. They keep in the refrigerator for 4 days and freeze well for up to 3 months.","timer":0}]','[{"original":"breadcrumbs","swap":"rolled oats blended fine or almond flour for a gluten-free option"},{"original":"Parmesan cheese","swap":"nutritional yeast for a dairy-free version"},{"original":"fresh parsley","swap":"fresh basil or dried parsley using half the amount"}]','["Overmixing the meat mixture which breaks down the protein strands and creates a tough dense texture","Making meatballs of different sizes which causes some to overcook while others remain undercooked","Skipping the internal temperature check and relying on color alone which can be misleading with turkey"]','["high protein","meal prep","Italian","freezer friendly","lean"]','["gluten-free adaptable","dairy-free adaptable"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Shrimp Stir Fry','shrimp-stir-fry','A fast and vibrant shrimp stir fry loaded with colorful vegetables and a savory ginger soy sauce. Everything comes together in one pan in under 20 minutes for a complete high protein meal.','Quick one-pan shrimp and vegetable stir fry with a bold savory sauce ready in 20 minutes.','Asian','Easy',10,10,20,2,320,38,18,10,4,'[{"amount":400,"unit":"g","item":"large shrimp peeled and deveined","group":"protein"},{"amount":2,"unit":"cups","item":"broccoli florets","group":"vegetables"},{"amount":1,"unit":"whole","item":"red bell pepper sliced thin","group":"vegetables"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":1,"unit":"tbsp","item":"fresh ginger grated","group":"aromatics"},{"amount":3,"unit":"tbsp","item":"low sodium soy sauce","group":"sauce"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"fat"},{"amount":1,"unit":"tbsp","item":"cornstarch","group":"sauce"}]','[{"title":"Prepare the sauce and ingredients","text":"Whisk together soy sauce, cornstarch and two tablespoons of water in a small bowl until smooth. Set aside. Pat shrimp completely dry with paper towels as moisture will prevent proper browning in the pan.","timer":0},{"title":"Heat the wok or skillet","text":"Heat a large wok or heavy skillet over high heat until it is very hot and just beginning to smoke. Add sesame oil and swirl to coat the surface. High heat is essential for proper stir fry texture.","timer":90},{"title":"Cook the shrimp","text":"Add the shrimp in a single layer and cook undisturbed for 90 seconds until pink on the bottom. Flip each shrimp and cook for another 60 seconds. Remove shrimp from the pan and set aside on a plate.","timer":150},{"title":"Stir fry the vegetables","text":"In the same pan add garlic and ginger and cook for 30 seconds stirring constantly. Add broccoli and bell pepper and stir fry on high heat for 3 to 4 minutes until tender-crisp with some charred edges.","timer":270},{"title":"Combine and finish","text":"Return the shrimp to the pan and pour the sauce over everything. Toss well and cook for one more minute until the sauce thickens and coats all the ingredients. Serve immediately over rice or cauliflower rice.","timer":60}]','[{"original":"shrimp","swap":"chicken breast sliced thin or firm tofu cubed for a vegetarian option"},{"original":"soy sauce","swap":"coconut aminos for a gluten-free lower sodium alternative"},{"original":"broccoli","swap":"snap peas, bok choy or any firm vegetable you have on hand"}]','["Adding wet shrimp to the pan which causes steaming and prevents that desirable golden sear","Using a pan that is not hot enough which makes vegetables go soft and limp instead of staying crisp","Overcrowding the pan with too many ingredients which drops the temperature and ruins the stir fry texture"]','["quick","high protein","low calorie","Asian","one pan","weeknight dinner"]','["gluten-free adaptable","dairy-free","paleo adaptable"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Egg White Omelette','egg-white-omelette','A light and protein-rich egg white omelette filled with spinach, mushrooms and feta cheese. It is the perfect low calorie high protein breakfast that takes less than 10 minutes to make.','Fluffy egg white omelette with vegetables and feta cheese ready in under 10 minutes.','American','Easy',5,7,12,1,180,26,5,6,1,'[{"amount":5,"unit":"whole","item":"egg whites","group":"protein"},{"amount":1,"unit":"cup","item":"fresh baby spinach","group":"vegetables"},{"amount":0.5,"unit":"cup","item":"mushrooms sliced","group":"vegetables"},{"amount":2,"unit":"tbsp","item":"crumbled feta cheese","group":"topping"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":1,"unit":"tsp","item":"olive oil","group":"fat"},{"amount":0.25,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"seasoning"}]','[{"title":"Whisk the egg whites","text":"Crack and separate 5 eggs collecting only the whites in a bowl. Add salt and pepper then whisk vigorously for one minute until slightly frothy. The air you incorporate here will make the omelette lighter and fluffier.","timer":60},{"title":"Saute the vegetables","text":"Heat olive oil in a non-stick skillet over medium heat. Add garlic and mushrooms and cook for 3 minutes until mushrooms are golden and most of their moisture has evaporated. Add spinach and stir until just wilted, about 30 seconds.","timer":210},{"title":"Remove filling and cook egg whites","text":"Push the vegetables to a plate temporarily. In the same pan pour in the whisked egg whites. Let them cook undisturbed for 60 to 90 seconds until the edges are set and opaque but the center is still slightly glossy.","timer":90},{"title":"Add filling and fold","text":"Spoon the sauteed vegetables onto one half of the egg white base. Sprinkle crumbled feta cheese over the vegetables. Use a spatula to gently fold the empty half of the omelette over the filled side.","timer":0},{"title":"Finish and serve","text":"Cook the folded omelette for another 30 seconds so the inside is fully set but not rubbery. Slide it onto a plate and serve immediately as egg whites become tough and chewy if left sitting.","timer":30}]','[{"original":"feta cheese","swap":"goat cheese or a light shredded mozzarella"},{"original":"mushrooms","swap":"diced bell peppers, cherry tomatoes or zucchini"},{"original":"fresh spinach","swap":"frozen spinach that has been thawed and squeezed very dry"}]','["Cooking on heat that is too high which makes the egg whites rubbery and browned on the outside","Adding the filling too early before the egg whites have set enough to hold together during folding","Not drying the mushrooms properly which releases water into the pan and makes the omelette soggy"]','["breakfast","high protein","low calorie","low fat","quick","vegetarian"]','["gluten-free","vegetarian","low carb","keto"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Greek Chicken Bowl','greek-chicken-bowl','A vibrant bowl loaded with juicy marinated chicken, fresh vegetables, and creamy tzatziki. This Mediterranean-inspired meal is wholesome and deeply satisfying.','A hearty Greek-inspired bowl with marinated chicken, crisp veggies, and tzatziki over rice.','Greek','Easy',15,20,35,2,520,45,38,18,5,'[{"amount":400,"unit":"g","item":"boneless skinless chicken breast","group":"protein"},{"amount":1,"unit":"cup","item":"cooked white rice","group":"base"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"marinade"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"marinade"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"marinade"},{"amount":0.5,"unit":"cup","item":"cherry tomatoes halved","group":"toppings"},{"amount":0.5,"unit":"cup","item":"cucumber diced","group":"toppings"},{"amount":0.25,"unit":"cup","item":"crumbled feta cheese","group":"toppings"},{"amount":0.5,"unit":"cup","item":"store-bought tzatziki","group":"sauce"}]','[{"title":"Marinate the Chicken","text":"Combine olive oil, oregano, garlic powder, salt, and pepper in a bowl. Add chicken breast and coat thoroughly. Let sit for at least 10 minutes.","timer":600},{"title":"Cook the Chicken","text":"Heat a skillet over medium-high heat. Cook the marinated chicken for 6 to 7 minutes per side until golden and cooked through to an internal temperature of 165F.","timer":840},{"title":"Rest and Slice","text":"Remove chicken from heat and let it rest for 5 minutes. Slice into thin strips against the grain.","timer":300},{"title":"Prepare Toppings","text":"While chicken rests, halve the cherry tomatoes and dice the cucumber. Set aside in small bowls.","timer":120},{"title":"Assemble the Bowl","text":"Divide cooked rice between two bowls. Top with sliced chicken, cherry tomatoes, cucumber, and feta cheese. Drizzle generously with tzatziki and serve immediately.","timer":60}]','[{"original":"white rice","swap":"cauliflower rice for a lower-carb option"},{"original":"chicken breast","swap":"chicken thighs for more flavor and juiciness"},{"original":"store-bought tzatziki","swap":"plain Greek yogurt mixed with dill and lemon juice"}]','["Skipping the resting period causes the chicken to lose its juices when sliced","Overcrowding the pan prevents proper browning and leads to steamed chicken","Using cold chicken straight from the fridge results in uneven cooking"]','["meal prep","high protein","Mediterranean","bowl","chicken"]','["gluten-free"]','Lunch','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Tuna Poke Bowl','tuna-poke-bowl','A fresh and colorful Hawaiian-inspired bowl featuring sushi-grade tuna tossed in a savory soy sesame marinade. It comes together in minutes with no cooking required.','A no-cook bowl with marinated sushi-grade tuna, rice, and vibrant toppings.','Hawaiian','Easy',15,0,15,2,480,38,45,12,4,'[{"amount":300,"unit":"g","item":"sushi-grade tuna cubed","group":"protein"},{"amount":2,"unit":"tbsp","item":"low-sodium soy sauce","group":"marinade"},{"amount":1,"unit":"tsp","item":"sesame oil","group":"marinade"},{"amount":1,"unit":"tsp","item":"rice vinegar","group":"marinade"},{"amount":2,"unit":"cups","item":"cooked sushi rice","group":"base"},{"amount":0.5,"unit":"cup","item":"edamame shelled","group":"toppings"},{"amount":0.5,"unit":"cup","item":"cucumber thinly sliced","group":"toppings"},{"amount":1,"unit":"tbsp","item":"sesame seeds","group":"garnish"},{"amount":2,"unit":"tbsp","item":"sliced green onions","group":"garnish"}]','[{"title":"Make the Marinade","text":"In a medium bowl, whisk together soy sauce, sesame oil, and rice vinegar until fully combined.","timer":60},{"title":"Marinate the Tuna","text":"Add the cubed sushi-grade tuna to the marinade. Gently toss to coat every piece and let it sit for 10 minutes in the refrigerator.","timer":600},{"title":"Prepare the Toppings","text":"Slice the cucumber, thaw the edamame if frozen, and prep your green onions and sesame seeds.","timer":120},{"title":"Build the Base","text":"Divide the cooked sushi rice evenly between two bowls and press gently to form a flat base.","timer":30},{"title":"Assemble and Serve","text":"Spoon the marinated tuna over the rice. Arrange cucumber slices and edamame around the tuna. Garnish with sesame seeds and green onions and serve immediately.","timer":60}]','[{"original":"sushi-grade tuna","swap":"sushi-grade salmon for a richer flavor"},{"original":"sushi rice","swap":"brown rice or quinoa for added fiber"},{"original":"soy sauce","swap":"coconut aminos for a gluten-free and lower-sodium option"}]','["Using non-sushi-grade fish is unsafe and should always be avoided for raw preparations","Over-marinating the tuna makes it mushy and ruins the texture","Using warm rice melts the tuna and negatively affects both texture and food safety"]','["no-cook","high protein","poke","bowl","seafood","Hawaiian"]','["dairy-free","gluten-free option"]','Lunch','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cottage Cheese Bowl','cottage-cheese-bowl','A simple and nourishing bowl built on a creamy cottage cheese base topped with fresh fruit and crunchy granola. It is ideal as a quick breakfast or a light snack.','A creamy high-protein bowl of cottage cheese layered with berries, honey, and granola.','American','Easy',5,0,5,1,380,28,42,8,4,'[{"amount":1,"unit":"cup","item":"full-fat cottage cheese","group":"base"},{"amount":0.5,"unit":"cup","item":"mixed fresh berries","group":"toppings"},{"amount":0.25,"unit":"cup","item":"granola","group":"toppings"},{"amount":1,"unit":"tbsp","item":"honey","group":"sweetener"},{"amount":1,"unit":"tbsp","item":"chia seeds","group":"toppings"},{"amount":0.25,"unit":"tsp","item":"cinnamon","group":"spice"},{"amount":1,"unit":"tbsp","item":"almond butter","group":"toppings"},{"amount":5,"unit":"whole","item":"almonds roughly chopped","group":"garnish"}]','[{"title":"Scoop the Base","text":"Add one full cup of cottage cheese to a wide shallow bowl and smooth it out gently with the back of a spoon.","timer":30},{"title":"Add Fruit Toppings","text":"Scatter the mixed fresh berries evenly over the cottage cheese for color and freshness.","timer":30},{"title":"Add Crunch and Texture","text":"Sprinkle granola, chia seeds, and roughly chopped almonds over the bowl for satisfying crunch.","timer":30},{"title":"Drizzle Toppings","text":"Add a dollop of almond butter and drizzle honey generously over the entire bowl.","timer":20},{"title":"Finish and Serve","text":"Dust lightly with cinnamon and serve immediately. Do not let it sit too long before eating or the granola will soften.","timer":10}]','[{"original":"full-fat cottage cheese","swap":"low-fat cottage cheese to reduce calorie content"},{"original":"granola","swap":"crushed rice cakes for a lighter and lower-calorie crunch"},{"original":"honey","swap":"maple syrup or agave nectar for a vegan-friendly sweetener"}]','["Using watery cottage cheese makes the bowl runny so drain it first if needed","Adding granola too early causes it to become soggy before eating","Overloading with too many toppings masks the flavor of the cottage cheese base"]','["breakfast","no-cook","high protein","quick","snack","bowl"]','["vegetarian","gluten-free option"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Protein Overnight Oats','protein-overnight-oats','These creamy overnight oats are packed with protein from Greek yogurt and protein powder, making them a powerful make-ahead breakfast. Just mix them the night before and wake up to a ready meal.','A thick and creamy make-ahead breakfast loaded with protein and topped with fresh fruit.','American','Easy',5,0,5,1,420,35,52,9,7,'[{"amount":0.5,"unit":"cup","item":"rolled oats","group":"base"},{"amount":0.5,"unit":"cup","item":"plain Greek yogurt","group":"base"},{"amount":0.5,"unit":"cup","item":"unsweetened almond milk","group":"liquid"},{"amount":1,"unit":"scoop","item":"vanilla protein powder","group":"protein"},{"amount":1,"unit":"tbsp","item":"chia seeds","group":"extras"},{"amount":1,"unit":"tbsp","item":"peanut butter","group":"extras"},{"amount":1,"unit":"tsp","item":"honey","group":"sweetener"},{"amount":0.5,"unit":"cup","item":"sliced banana or berries","group":"toppings"}]','[{"title":"Combine Dry Ingredients","text":"In a jar or container with a lid, add the rolled oats, chia seeds, and protein powder. Stir briefly to mix them together.","timer":30},{"title":"Add Wet Ingredients","text":"Pour in the almond milk and add the Greek yogurt and honey. Stir vigorously until the protein powder is fully dissolved and no clumps remain.","timer":60},{"title":"Add Peanut Butter","text":"Drop the peanut butter on top and gently swirl it into the mixture without fully combining to create pockets of flavor.","timer":20},{"title":"Refrigerate Overnight","text":"Seal the container and place it in the refrigerator for at least 6 hours or overnight to allow the oats to absorb the liquid fully.","timer":21600},{"title":"Top and Serve","text":"In the morning, remove from the fridge and stir gently. Add a splash more almond milk if needed to loosen the texture. Top with sliced banana or fresh berries and serve cold.","timer":60}]','[{"original":"almond milk","swap":"regular dairy milk for a creamier and richer consistency"},{"original":"vanilla protein powder","swap":"chocolate protein powder for a dessert-like flavor"},{"original":"peanut butter","swap":"almond butter or sunflower seed butter for a nut-free alternative"}]','["Not using enough liquid results in overly thick and dry oats that are hard to eat","Adding toppings the night before makes them soggy by morning","Using instant oats instead of rolled oats creates a mushy and unpleasant texture"]','["meal prep","make-ahead","breakfast","high protein","oats","no-cook"]','["vegetarian","gluten-free option"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Protein Smoothie','protein-smoothie','A thick and creamy blended smoothie loaded with protein from Greek yogurt and protein powder, plus natural energy from banana and oats. It is ready in under 5 minutes and perfect for post-workout recovery.','A rich and filling protein-packed smoothie blended with banana, yogurt, and protein powder.','American','Easy',5,0,5,1,390,40,44,7,4,'[{"amount":1,"unit":"scoop","item":"chocolate protein powder","group":"protein"},{"amount":1,"unit":"whole","item":"frozen banana","group":"base"},{"amount":0.5,"unit":"cup","item":"plain Greek yogurt","group":"protein"},{"amount":1,"unit":"cup","item":"unsweetened almond milk","group":"liquid"},{"amount":2,"unit":"tbsp","item":"rolled oats","group":"extras"},{"amount":1,"unit":"tbsp","item":"peanut butter","group":"extras"},{"amount":0.5,"unit":"cup","item":"ice cubes","group":"texture"},{"amount":1,"unit":"tsp","item":"honey","group":"sweetener"}]','[{"title":"Add Liquid First","text":"Pour the almond milk into the blender first. This protects the blades and helps everything blend smoothly from the start.","timer":15},{"title":"Add Soft Ingredients","text":"Add the Greek yogurt, peanut butter, honey, and rolled oats to the blender on top of the liquid.","timer":30},{"title":"Add Frozen Ingredients","text":"Add the frozen banana and ice cubes on top of everything. Adding frozen items last helps the blender work more efficiently.","timer":20},{"title":"Add Protein Powder","text":"Sprinkle the protein powder on top of the other ingredients. Do not add it directly to the liquid first as it can clump.","timer":15},{"title":"Blend and Serve","text":"Blend on high for 45 to 60 seconds until completely smooth and creamy. Pour into a tall glass and consume immediately for the best texture and flavor.","timer":60}]','[{"original":"almond milk","swap":"oat milk for a naturally sweeter and creamier base"},{"original":"frozen banana","swap":"frozen mango for a tropical flavor twist"},{"original":"peanut butter","swap":"cashew butter for a milder and slightly sweeter taste"}]','["Adding protein powder before the liquid causes it to clump and blend unevenly","Using a fresh banana instead of a frozen one results in a thin and watery smoothie","Over-blending heats the smoothie and ruins its cold and creamy texture"]','["post-workout","high protein","smoothie","quick","blender","breakfast"]','["vegetarian","gluten-free option"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Lentil Soup','classic-lentil-soup','A hearty and nourishing soup packed with red lentils, vegetables, and warm spices. This simple one-pot meal is filling, affordable, and full of plant-based protein.','A warm and comforting red lentil soup ready in under an hour.','Mediterranean','Easy',10,35,45,4,280,16,42,6,14,'[{"amount":1.5,"unit":"cups","item":"red lentils rinsed","group":"main"},{"amount":1,"unit":"medium","item":"onion diced","group":"vegetables"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"vegetables"},{"amount":2,"unit":"medium","item":"carrots diced","group":"vegetables"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"fat"},{"amount":1,"unit":"teaspoon","item":"ground cumin","group":"spices"},{"amount":1,"unit":"teaspoon","item":"smoked paprika","group":"spices"},{"amount":5,"unit":"cups","item":"vegetable broth","group":"liquid"},{"amount":1,"unit":"can","item":"diced tomatoes","group":"vegetables"},{"amount":1,"unit":"teaspoon","item":"salt","group":"seasoning"}]','[{"title":"Saute the aromatics","text":"Heat olive oil in a large pot over medium heat. Add diced onion and carrots and cook for 5 minutes until softened. Add garlic and cook for 1 more minute.","timer":360},{"title":"Add spices","text":"Stir in the cumin and smoked paprika and cook for 30 seconds to bloom the spices. This step builds a deep flavor base for the soup.","timer":30},{"title":"Add lentils and liquid","text":"Pour in the rinsed lentils, diced tomatoes, and vegetable broth. Stir everything together and bring the pot to a boil.","timer":300},{"title":"Simmer until lentils are tender","text":"Reduce heat to low and simmer uncovered for 25 minutes until lentils are completely soft and starting to fall apart. Stir occasionally.","timer":1500},{"title":"Season and serve","text":"Add salt and taste for seasoning. For a creamier texture blend half the soup using an immersion blender. Serve hot with crusty bread.","timer":0}]','[{"original":"red lentils","swap":"green or brown lentils with 10 extra minutes of cooking"},{"original":"vegetable broth","swap":"chicken broth or water with extra seasoning"},{"original":"olive oil","swap":"coconut oil or any neutral cooking oil"}]','["Do not skip rinsing the lentils as they can carry dust and debris","Do not boil the soup on high heat the entire time as it causes lentils to break down unevenly","Do not add salt too early as it can slow the softening of lentils"]','["soup","lentils","vegetarian","budget","one-pot","healthy"]','["vegan","gluten-free","dairy-free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Rice and Beans','classic-rice-and-beans','A simple and satisfying combination of fluffy white rice and seasoned black beans cooked together with aromatics. This dish is a complete protein source and an everyday staple across many cultures.','Fluffy rice paired with savory seasoned black beans for a complete and affordable meal.','Latin American','Easy',10,30,40,4,320,12,58,5,10,'[{"amount":1.5,"unit":"cups","item":"long grain white rice","group":"main"},{"amount":2,"unit":"cans","item":"black beans drained and rinsed","group":"main"},{"amount":1,"unit":"medium","item":"onion diced","group":"vegetables"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"vegetables"},{"amount":1,"unit":"medium","item":"green bell pepper diced","group":"vegetables"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"fat"},{"amount":1,"unit":"teaspoon","item":"ground cumin","group":"spices"},{"amount":1,"unit":"teaspoon","item":"dried oregano","group":"spices"},{"amount":3,"unit":"cups","item":"water","group":"liquid"},{"amount":1,"unit":"teaspoon","item":"salt","group":"seasoning"}]','[{"title":"Cook the rice","text":"Rinse the rice under cold water until it runs clear. Combine with 3 cups of water and half a teaspoon of salt in a saucepan. Bring to a boil then reduce heat, cover, and cook for 18 minutes.","timer":1080},{"title":"Saute vegetables","text":"While rice cooks, heat olive oil in a skillet over medium heat. Add onion and bell pepper and cook for 5 minutes until softened. Add garlic and cook for 1 more minute.","timer":360},{"title":"Season the base","text":"Add cumin and oregano to the vegetable mixture and stir for 30 seconds. This creates a fragrant sofrito base for the beans.","timer":30},{"title":"Add and simmer the beans","text":"Add drained black beans and half a cup of water to the skillet. Simmer for 10 minutes until the beans absorb the flavors and the liquid slightly thickens.","timer":600},{"title":"Combine and serve","text":"Fluff the rice with a fork and season with remaining salt. Serve beans over or alongside the rice. Garnish with fresh cilantro if desired.","timer":0}]','[{"original":"black beans","swap":"kidney beans or pinto beans"},{"original":"white rice","swap":"brown rice with 15 extra minutes of cooking time"},{"original":"green bell pepper","swap":"red bell pepper or celery for a different flavor"}]','["Do not skip rinsing the rice as excess starch makes it gummy","Do not lift the lid while rice is cooking as it releases steam and affects texture","Do not overcook the beans in the skillet or they will become mushy"]','["rice","beans","budget","vegetarian","protein","staple"]','["vegan","gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Budget Egg Fried Rice','budget-egg-fried-rice','A quick and satisfying fried rice made with leftover rice, eggs, and pantry staples for almost no cost. This recipe transforms simple ingredients into a flavorful and filling meal in minutes.','A fast and cheap egg fried rice using leftover rice and basic pantry ingredients.','Chinese','Easy',5,10,15,2,390,14,52,14,2,'[{"amount":2,"unit":"cups","item":"cooked rice preferably day-old","group":"main"},{"amount":3,"unit":"large","item":"eggs beaten","group":"protein"},{"amount":3,"unit":"tablespoons","item":"soy sauce","group":"seasoning"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":3,"unit":"stalks","item":"green onions chopped","group":"vegetables"},{"amount":1,"unit":"cup","item":"frozen peas","group":"vegetables"},{"amount":2,"unit":"tablespoons","item":"vegetable oil","group":"fat"},{"amount":1,"unit":"teaspoon","item":"sesame oil","group":"fat"},{"amount":0.5,"unit":"teaspoon","item":"white pepper","group":"seasoning"}]','[{"title":"Prep and heat the wok","text":"Make sure your cooked rice is broken up with no large clumps. Heat a wok or large skillet over high heat until it begins to smoke. Add vegetable oil and swirl to coat.","timer":120},{"title":"Cook the eggs","text":"Pour beaten eggs into the hot wok and scramble quickly for about 30 seconds until just set but still slightly wet. Push eggs to the side of the wok.","timer":30},{"title":"Add garlic and rice","text":"Add garlic to the empty side of the wok and stir for 15 seconds. Add the rice and press it flat against the wok surface. Stir-fry everything together for 3 minutes.","timer":180},{"title":"Add vegetables and seasoning","text":"Toss in the frozen peas and pour soy sauce over the rice. Stir-fry for 2 more minutes until peas are heated through and everything is evenly coated.","timer":120},{"title":"Finish and serve","text":"Remove from heat and drizzle sesame oil over the rice. Add white pepper and toss with green onions. Serve immediately while hot.","timer":0}]','[{"original":"frozen peas","swap":"any frozen vegetable or leftover cooked vegetables"},{"original":"soy sauce","swap":"tamari for a gluten-free option or coconut aminos"},{"original":"sesame oil","swap":"a small amount of butter for a different but rich finish"}]','["Do not use freshly cooked hot rice as it creates steam and makes the dish soggy","Do not cook on low heat as high heat is essential for proper wok flavor","Do not add too much soy sauce at once as it is easier to add more than to fix an overly salty dish"]','["fried rice","eggs","budget","quick","leftovers","Asian"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pasta Aglio e Olio','pasta-aglio-e-olio','A traditional Italian pasta dish made with just spaghetti, garlic, olive oil, and chili flakes. It is one of the most elegant and minimal dishes in Italian cooking with incredible depth of flavor.','Simple spaghetti tossed with golden garlic and chili-infused olive oil for a perfect weeknight meal.','Italian','Easy',5,20,25,2,520,14,68,22,3,'[{"amount":200,"unit":"grams","item":"spaghetti","group":"main"},{"amount":6,"unit":"cloves","item":"garlic thinly sliced","group":"aromatics"},{"amount":5,"unit":"tablespoons","item":"extra virgin olive oil","group":"fat"},{"amount":0.5,"unit":"teaspoon","item":"red chili flakes","group":"spices"},{"amount":0.25,"unit":"cup","item":"fresh parsley chopped","group":"garnish"},{"amount":1,"unit":"teaspoon","item":"salt for pasta water","group":"seasoning"},{"amount":0.5,"unit":"cup","item":"reserved pasta cooking water","group":"liquid"},{"amount":3,"unit":"tablespoons","item":"grated Parmesan cheese","group":"topping"}]','[{"title":"Boil the pasta","text":"Bring a large pot of water to a boil and add a generous teaspoon of salt. Cook spaghetti according to package directions until al dente. Reserve half a cup of pasta water before draining.","timer":900},{"title":"Slowly infuse the oil","text":"While pasta cooks, heat olive oil in a large skillet over low heat. Add sliced garlic and cook very slowly for 8 to 10 minutes until golden and fragrant. Do not let it burn.","timer":600},{"title":"Add chili flakes","text":"Add the red chili flakes to the golden garlic oil and stir for 30 seconds to release their heat and flavor into the oil.","timer":30},{"title":"Toss pasta in the sauce","text":"Add the drained spaghetti directly to the skillet and toss over medium heat. Add reserved pasta water a splash at a time and toss vigorously to emulsify a silky sauce around the pasta.","timer":120},{"title":"Finish and plate","text":"Remove from heat and toss with fresh parsley. Divide into bowls and top with grated Parmesan. Serve immediately.","timer":0}]','[{"original":"spaghetti","swap":"linguine or any long pasta such as bucatini"},{"original":"Parmesan cheese","swap":"Pecorino Romano or nutritional yeast for a dairy-free option"},{"original":"fresh parsley","swap":"fresh basil or dried parsley flakes"}]','["Do not cook garlic on high heat as it will burn and turn bitter very quickly","Do not forget to save pasta water as it is essential for creating an emulsified sauce","Do not drain pasta completely dry before adding to the skillet as residual moisture helps the sauce form"]','["pasta","Italian","quick","garlic","budget","simple"]','["vegetarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Potato Soup','creamy-potato-soup','A thick and comforting potato soup made with russet potatoes, onion, and a creamy broth base. It is a simple and budget-friendly recipe that feels indulgent without requiring expensive ingredients.','A rich and creamy potato soup that is hearty enough to serve as a full meal.','American','Easy',10,30,40,4,340,9,48,13,4,'[{"amount":4,"unit":"large","item":"russet potatoes peeled and diced","group":"main"},{"amount":1,"unit":"medium","item":"onion diced","group":"vegetables"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":2,"unit":"tablespoons","item":"butter","group":"fat"},{"amount":4,"unit":"cups","item":"chicken broth","group":"liquid"},{"amount":1,"unit":"cup","item":"whole milk","group":"dairy"},{"amount":0.5,"unit":"cup","item":"sour cream","group":"dairy"},{"amount":1,"unit":"teaspoon","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"teaspoon","item":"black pepper","group":"seasoning"},{"amount":3,"unit":"stalks","item":"green onions chopped for garnish","group":"garnish"}]','[{"title":"Saute aromatics","text":"Melt butter in a large pot over medium heat. Add diced onion and cook for 5 minutes until translucent. Add garlic and stir for 1 minute until fragrant.","timer":360},{"title":"Add potatoes and broth","text":"Add diced potatoes and pour in the chicken broth. Bring the pot to a boil then reduce heat to medium-low. Simmer for 20 minutes until potatoes are completely fork-tender.","timer":1200},{"title":"Mash or blend","text":"Use a potato masher to mash about half the potatoes directly in the pot for a chunky texture. For a smooth soup use an immersion blender to blend fully.","timer":120},{"title":"Add dairy and season","text":"Stir in the whole milk and sour cream over low heat. Do not boil after adding dairy or it may curdle. Season with salt and black pepper and stir until smooth.","timer":180},{"title":"Serve with toppings","text":"Ladle the soup into bowls and garnish with chopped green onions. Optional toppings include shredded cheddar cheese or crispy bacon bits.","timer":0}]','[{"original":"sour cream","swap":"plain Greek yogurt or cream cheese for a similar creamy tang"},{"original":"whole milk","swap":"heavy cream for a richer soup or unsweetened oat milk for dairy-free"},{"original":"chicken broth","swap":"vegetable broth to make the recipe fully vegetarian"}]','["Do not add dairy while the soup is still boiling as it will cause the milk and sour cream to curdle","Do not cut potatoes into large uneven pieces as they will cook at different rates","Do not skip the mashing step as blending entirely can make the starch too thick and gluey"]','["soup","potato","comfort food","budget","creamy","winter"]','["gluten-free","vegetarian"]','Soup','ai');